,'Tầm nhìn, sứ mệnh',300,'<div><strong>Tầm nh&igrave;n:</strong> <br />\r\n<br />\r\nGAKIBI ALC quyết t&acirc;m đến năm 2020 trở th&agrave;nh thương hiệu gạch b&ecirc; t&ocirc;ng kh&iacute; chưng &aacute;p lớn nhất Việt Nam.</div>\r\n<div>&nbsp;</div>\r\n<div><strong>Sứ mệnh:</strong> <br />\r\n<br />\r\nGAKIBI ALC phấn đấu l&agrave; thương hiệu vật liệu x&acirc;y dựng h&agrave;ng đầu về xanh, sạch v&agrave; th&acirc;n thiện với m&ocirc;i trường. Đồng thời đem lại cho c&aacute;c kh&aacute;ch h&agrave;ng những gi&aacute; trị kinh tế v&agrave; sử dụng hiệu quả nhất.</div>',45,2,'?m=htmlpage&idF=300_300&id_htmlpage=6&','','',NULL,'htmlpage','vn',1,'tam-nhin-su-menh/tam-nhin-su-menh/',0,6,'default',48,NULL,NULL,NULL),(502,'GAKIBI ALC panels',163,'GAKIBI ALC panel is aerated concrete configuration of special anti-rust treated steel mesh made of lightweight, high strength building products.',61,32,'?m=product&idF=163_502&','AAL8O2LG_alcblock_gakibi-alc-panels.jpg','',NULL,'product','en',1,'products/gakibi-alc-panels/',0,0,'default',0,NULL,NULL,NULL),(490,'Manufacturing process',110,'&nbsp;',45,23,'?m=htmlpage&idF=110_490&id_htmlpage=69&','','',NULL,'htmlpage','en',1,'about-us/manufacturing-process/',0,69,'default',0,NULL,NULL,NULL),(397,'Factories, enterprises',354,'&nbsp;',45,53,'?m=htmlpage&idF=354_397&id_htmlpage=85&','','',NULL,'htmlpage','en',1,'applications/factories-enterprises/',0,85,'default',0,NULL,NULL,NULL),(351,'Solutions',0,'Our searchable database of more than 50 solution notes contains specific information on procedures and equipment for performing a wide variety of thickness gaging, flaw detection, and material analysis tests on metals, plastics, ceramics, composites, and other materials.<br />\r\nTo make our solutions as easily accessible as possible, you can now browse them by applications and by industries...',45,4,'?m=htmlpage&idF=351&id_htmlpage=91&','','',NULL,'htmlpage','en',1,'en/solutions/',0,91,'default',0,NULL,NULL,NULL),(352,'Documents',0,'&nb