  `del` bigint(1) DEFAULT 1,
  `pdf` varchar(255) DEFAULT NULL,
  UNIQUE KEY `id` (`id`),
  FULLTEXT KEY `title` (`title`,`content`)
) ENGINE=MyISAM AUTO_INCREMENT=9 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci;
