INSERT INTO `sys_htmlpage` VALUES (1,'Về chúng tôi','2022-08-10',NULL,31,NULL,'<div style=\"background:#eeeeee; border:1px solid #cccccc; padding:5px 10px; text-align:center\"><span style=\"color:#27ae60\"><span style=\"font-size:22px\"><strong>C&Ocirc;NG TY CỔ PHẦN TM QUỐC TẾ THUẬN PH&Aacute;T</strong></span></span></div>\r\n\r\n<h2 style=\"text-align:center\">&nbsp;</h2>\r\n\r\n<h2 style=\"text-align:center\"><span style=\"color:#2ecc71\"><u><span style=\"font-size:20px\">Điểm Tựa Vững Chắc Cho Cuộc Sống Xanh &ndash; Khỏe &ndash; Đẹp &ndash; An To&agrave;n</span></u></span></h2>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:20px\">&nbsp; &nbsp; Được th&agrave;nh lập v&agrave;o ng&agrave;y 29 th&aacute;ng 07 năm 2025, <strong>C&ocirc;ng ty Cổ phần TM Quốc tế Thuận Ph&aacute;t</strong> l&agrave; doanh nghiệp ti&ecirc;n phong trong lĩnh vực thương mại v&agrave; xuất nhập khẩu c&aacute;c giải ph&aacute;p chăm s&oacute;c sức khỏe chủ động.</span></p>\r\n\r\n<p><span style=\"font-size:20px\">&nbsp; &nbsp; Với tư duy đổi mới, Thuận Ph&aacute;t kh&ocirc;ng ngừng hợp t&aacute;c chiến lược c&ugrave;ng c&aacute;c chuy&ecirc;n gia h&agrave;ng đầu để nghi&ecirc;n cứu, ứng dụng những c&ocirc;ng nghệ ti&ecirc;n tiến nhất. Ch&uacute;ng t&ocirc;i tập trung khai ph&aacute; c&aacute;c tiềm năng s&acirc;u thẳm b&ecirc;n trong cơ thể con người, từ đ&oacute; kiến tạo một cộng đồng sống vui, sống khỏe, mang lại giải ph&aacute;p chăm s&oacute;c sức khỏe v&agrave; sắc đẹp to&agrave;n diện cho to&agrave;n x&atilde; hội.</span></p>\r\n\r\n<p><span style=\"font-size:20px\">&nbsp; &nbsp; Thuận Ph&aacute;t quyết t&acirc;m khẳng định vị thế thương hiệu, trở th&agrave;nh biểu tượng của niềm tin trọn vẹn v&agrave; l&agrave; người bạn đồng h&agrave;nh kh&ocirc;ng thể thiếu tr&ecirc;n h&agrave;nh tr&igrave;nh n&acirc;ng cao chất lượng cuộc sống của mỗi gia đ&igrave;nh Việt Nam.</span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"margin-left:360px\"><span style=\"font-size:20px\"><img alt=\"\" style=\"height:!important;width:!important;\" src=\"/image/Leramat3.jpg\" style=\"height:!important; width:!important\" />&nbsp;&nbsp;</span></p>\r\n\r\n<h2><span style=\"color:#e74c3c\"><span style=\"font-size:22px\"><strong>TẦM NH&Igrave;N</strong></span></span></h2>\r\n\r\n<p><span style=\"font-size:20px\">Phấn đấu trở th&agrave;nh biểu tượng niềm tin h&agrave;ng đầu trong lĩnh vực thực phẩm dinh dưỡng an to&agrave;n v&agrave; chất lượng cao. Thuận Ph&aacute;t hướng tới mục ti&ecirc;u đ&aacute;p ứng trọn vẹn nhu cầu dinh dưỡng đa dạng của cộng đồng, kiến tạo một tương lai nơi mọi người d&acirc;n đều được tận hưởng cuộc sống khỏe mạnh, hạnh ph&uacute;c v&agrave; tr&agrave;n đầy năng lượng.</span></p>\r\n\r\n<h2><span style=\"color:#e74c3c\"><span style=\"font-size:22px\"><strong>SỨ MỆNH</strong></span></span></h2>\r\n\r\n<ul>\r\n	<li>\r\n	<p><span style=\"font-size:20px\"><span style=\"color:#27ae60\"><strong>Lan tỏa tri thức:</strong></span> Tổ chức chuỗi hoạt động truyền th&ocirc;ng, gi&aacute;o dục v&agrave; tư vấn chuy&ecirc;n s&acirc;u nhằm n&acirc;ng cao nhận thức của cộng đồng về vai tr&ograve; của dinh dưỡng l&agrave;nh mạnh.</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:20px\"><span style=\"color:#27ae60\"><strong>N&acirc;ng tầm thể chất:</strong></span> G&oacute;p phần tối ưu h&oacute;a sự ph&aacute;t triển to&agrave;n diện về cả thể chất, tr&iacute; tuệ lẫn tinh thần của người Việt th&ocirc;ng qua c&aacute;c sản phẩm đạt chuẩn quốc tế.</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:20px\"><span style=\"color:#27ae60\"><strong>Ph&aacute;t triển bền vững:</strong></span> Đồng h&agrave;nh c&ugrave;ng sự trường thọ v&agrave; sức khỏe của thế hệ h&ocirc;m nay v&agrave; mai sau, v&igrave; lợi &iacute;ch tối cao của người ti&ecirc;u d&ugrave;ng.</span></p>\r\n	</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p style=\"margin-left:360px\"><span style=\"font-size:20px\"><img alt=\"\" style=\"height:!important;width:!important;\" src=\"/image/Leramat2.jpg\" style=\"height:!important; width:!important\" /></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h2><span style=\"color:#e74c3c\"><span style=\"font-size:22px\"><strong>GI&Aacute; TRỊ CỐT L&Otilde;I</strong></span></span></h2>\r\n\r\n<p><span style=\"font-size:20px\">Gi&aacute; trị cốt l&otilde;i của Thuận Ph&aacute;t được định h&igrave;nh qua 4 dung h&ograve;a vững chắc: <span style=\"color:#c0392b\"><strong>Ch&iacute;nh trực &ndash; Tu&acirc;n thủ &ndash; Tin tưởng &ndash; Tr&aacute;ch nhiệm.</strong></span></span></p>\r\n\r\n<h3><span style=\"color:#27ae60\"><span style=\"font-size:20px\"><strong>1. Ch&iacute;nh Trực</strong></span></span></h3>\r\n\r\n<p><span style=\"font-size:20px\">Thuận Ph&aacute;t đặt t&iacute;nh trung thực v&agrave; ngay thẳng l&ecirc;n h&agrave;ng đầu trong mọi quy tr&igrave;nh vận h&agrave;nh. Ch&uacute;ng t&ocirc;i cam kết kh&ocirc;ng lừa dối đối t&aacute;c, kh&aacute;ch h&agrave;ng v&agrave; lu&ocirc;n cung cấp những sản phẩm mang lại gi&aacute; trị thực sự.</span></p>\r\n\r\n<h3><span style=\"color:#27ae60\"><span style=\"font-size:20px\"><strong>2. Tu&acirc;n Thủ</strong></span></span></h3>\r\n\r\n<p><span style=\"font-size:20px\">Mọi hoạt động giao tiếp, hợp t&aacute;c nội bộ cũng như với đối t&aacute;c v&agrave; kh&aacute;ch h&agrave;ng đều được thực hiện dựa tr&ecirc;n sự t&ocirc;n trọng tuyệt đối c&aacute;c quy tr&igrave;nh, nguy&ecirc;n tắc v&agrave; quy định ph&aacute;p luật.</span></p>\r\n\r\n<h3><span style=\"color:#27ae60\"><span style=\"font-size:20px\"><strong>3. Tin Tưởng</strong></span></span></h3>\r\n\r\n<p><span style=\"font-size:20px\">Ch&uacute;ng t&ocirc;i x&acirc;y dựng niềm tin từ chất lượng gốc rễ của sản phẩm, từ đ&oacute; lan tỏa những gi&aacute; trị nh&acirc;n văn đến mạng lưới đối t&aacute;c, c&aacute;c nh&agrave; ph&acirc;n phối v&agrave; nhận lại sự t&iacute;n nhiệm d&agrave;i l&acirc;u từ kh&aacute;ch h&agrave;ng.</span></p>\r\n\r\n<h3><span style=\"color:#27ae60\"><span style=\"font-size:20px\"><strong>4. Tr&aacute;ch Nhiệm</strong></span></span></h3>\r\n\r\n<blockquote>\r\n<ul>\r\n	<li>\r\n	<p><span style=\"font-size:20px\"><span style=\"color:#e74c3c\"><strong>Với Quốc gia:</strong></span> G&oacute;p phần nu&ocirc;i dưỡng v&agrave; ph&aacute;t triển to&agrave;n diện cho c&aacute;c thế hệ tương lai th&ocirc;ng qua nguồn dinh dưỡng chuẩn mực.</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:20px\"><span style=\"color:#e74c3c\"><strong>Với Cộng sự:</strong> </span>Kiến tạo m&ocirc;i trường l&agrave;m việc đo&agrave;n kết, vững mạnh, mang lại cơ hội tạo nguồn thu nhập thụ động bền vững cho tất cả th&agrave;nh vi&ecirc;n.</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:20px\"><span style=\"color:#e74c3c\"><strong>Với Đối t&aacute;c &amp; Nh&agrave; ph&acirc;n phối:</strong></span> Thiết lập chuỗi gi&aacute; trị cộng hưởng, c&ugrave;ng hợp t&aacute;c v&agrave; c&ugrave;ng ph&aacute;t triển thịnh vượng.</span></p>\r\n	</li>\r\n	<li>\r\n	<p><span style=\"font-size:20px\"><span style=\"color:#e74c3c\"><strong>Với Kh&aacute;ch h&agrave;ng (Trọng t&acirc;m nhất):</strong></span> Cam kết mang đến nguồn dinh dưỡng <strong>NGON &ndash; BỔ &ndash; AN TO&Agrave;N</strong> tuyệt đối cho người ti&ecirc;u d&ugrave;ng.</span></p>\r\n	</li>\r\n</ul>\r\n</blockquote>\r\n\r\n<h3><span style=\"font-size:20px\"><u><strong>KỶ NIỆM CHƯƠNG CỦA HỘI Y DƯỢC HỌC VIỆT NAM&nbsp;</strong></u></span></h3>\r\n\r\n<h3><br />\r\n<span style=\"font-size:20px\"><img style=\"height:!important;width:!important;\" src=\"http://thuanphatitc.local/image/Kyniemchuong.jpg\" style=\"height:!important; width:!important\" /></span></h3>\r\n',1,'vn',1,'BEN4SMSH_Kyniemchuong.jpg'),(7,'Chính sách & quyền lợi Affiliate (tiếp thị liên kết)','2025-08-05',NULL,31,NULL,'<p>Bất kỳ ai cũng c&oacute; thể đăng k&yacute; trở th&agrave;nh cộng t&aacute;c vi&ecirc;n online v&agrave; tham gia hệ thống ph&acirc;n phối sản phẩm Thuận Ph&aacute;t th&ocirc;ng qua đường dẫn Affiliate (tiếp thị li&ecirc;n kết).</p>\r\n\r\n<p>&nbsp;</p>\r\n',1,'vn',1,''),(8,'Chính sách bảo mật','2025-09-10',NULL,31,NULL,'<p style=\"text-align:justify\"><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><img alt=\"yes\" style=\"height:!important;width:!important;\" src=\"https://cdn.ckeditor.com/4.19.1/full/plugins/smiley/images/thumbs_up.png\" style=\"height:!important; width:!important\" title=\"yes\" />Ch&uacute;ng t&ocirc;i nghi&ecirc;m t&uacute;c thực hiện tr&aacute;ch nhiệm của m&igrave;nh li&ecirc;n quan đến bảo mật th&ocirc;ng tin theo c&aacute;c quy định về bảo vệ b&iacute; mật th&ocirc;ng tin c&aacute; nh&acirc;n của ph&aacute;p luật Việt Nam (&ldquo;Luật ri&ecirc;ng tư&rdquo;) v&agrave; cam kết t&ocirc;n trọng quyền ri&ecirc;ng tư v&agrave; sự quan t&acirc;m của tất cả người d&ugrave;ng đối với website. Người d&ugrave;ng c&oacute; nghĩa l&agrave; người đăng k&yacute; t&agrave;i khoản với ch&uacute;ng t&ocirc;i để sử dụng c&aacute;c Dịch Vụ. Ch&uacute;ng t&ocirc;i nhận biết tầm quan trọng của dữ liệu c&aacute; nh&acirc;n m&agrave; bạn đ&atilde; tin tưởng giao cho ch&uacute;ng t&ocirc;i v&agrave; tin rằng ch&uacute;ng t&ocirc;i c&oacute; tr&aacute;ch nhiệm quản l&yacute;, bảo vệ v&agrave; xử l&yacute; dữ liệu c&aacute; nh&acirc;n của bạn một c&aacute;ch th&iacute;ch hợp. Ch&iacute;nh s&aacute;ch bảo mật n&agrave;y (&quot;Ch&iacute;nh s&aacute;ch bảo mật&quot; hay &quot;Ch&iacute;nh s&aacute;ch&quot;) được thiết kế để gi&uacute;p bạn hiểu được c&aacute;ch thức ch&uacute;ng t&ocirc;i thu thập, sử dụng, tiết lộ v&agrave;/hoặc xử l&yacute; dữ liệu c&aacute; nh&acirc;n m&agrave; bạn đ&atilde; cung cấp cho ch&uacute;ng t&ocirc;i v&agrave;/hoặc lưu giữ về bạn, cho d&ugrave; l&agrave; hiện nay hoặc trong tương lai, cũng như để gi&uacute;p bạn đưa ra quyết định s&aacute;ng suốt trước khi cung cấp cho ch&uacute;ng t&ocirc;i bất kỳ dữ liệu c&aacute; nh&acirc;n n&agrave;o của bạn.</span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><img alt=\"yes\" style=\"height:!important;width:!important;\" src=\"https://cdn.ckeditor.com/4.19.1/full/plugins/smiley/images/thumbs_up.png\" style=\"height:!important; width:!important\" title=\"yes\" />&quot;Dữ Liệu C&aacute; Nh&acirc;n&quot; hay &quot;dữ liệu c&aacute; nh&acirc;n&quot; c&oacute; nghĩa l&agrave; dữ liệu, d&ugrave; đ&uacute;ng hay kh&ocirc;ng, về một c&aacute; nh&acirc;n m&agrave; th&ocirc;ng qua đ&oacute; c&oacute; thể được x&aacute;c định được danh t&iacute;nh, hoặc từ dữ liệu đ&oacute; v&agrave; th&ocirc;ng tin kh&aacute;c m&agrave; một tổ chức c&oacute; hoặc c&oacute; khả năng tiếp cận. C&aacute;c v&iacute; dụ thường gặp về dữ liệu c&aacute; nh&acirc;n c&oacute; thể gồm c&oacute; t&ecirc;n, số chứng minh nh&acirc;n d&acirc;n v&agrave; th&ocirc;ng tin li&ecirc;n hệ.</span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><img alt=\"yes\" style=\"height:!important;width:!important;\" src=\"https://cdn.ckeditor.com/4.19.1/full/plugins/smiley/images/thumbs_up.png\" style=\"height:!important; width:!important\" title=\"yes\" />Bằng việc sử dụng c&aacute;c Dịch Vụ, đăng k&yacute; một t&agrave;i khoản với ch&uacute;ng t&ocirc;i, bạn x&aacute;c nhận v&agrave; đồng &yacute; rằng bạn chấp nhận c&aacute;c phương ph&aacute;p, y&ecirc;u cầu, v&agrave;/hoặc ch&iacute;nh s&aacute;ch được m&ocirc; tả trong Ch&iacute;nh s&aacute;ch bảo mật n&agrave;y v&agrave; theo đ&acirc;y bạn x&aacute;c nhận bạn đ&atilde; biết r&otilde; v&agrave; đồng &yacute; to&agrave;n bộ cho ph&eacute;p ch&uacute;ng t&ocirc;i thu thập, sử dụng, tiết lộ v&agrave;/hoặc xử l&yacute; dữ liệu c&aacute; nh&acirc;n của bạn như m&ocirc; tả trong đ&acirc;y. <strong>NẾU BẠN KH&Ocirc;NG ĐỒNG &Yacute; CHO PH&Eacute;P XỬ L&Yacute; DỮ LIỆU C&Aacute; NH&Acirc;N CỦA BẠN NHƯ M&Ocirc; TẢ TRONG CH&Iacute;NH S&Aacute;CH N&Agrave;Y, VUI L&Ograve;NG KH&Ocirc;NG SỬ DỤNG C&Aacute;C DỊCH VỤ CỦA CH&Uacute;NG T&Ocirc;I HAY TRANG WEB CỦA CH&Uacute;NG T&Ocirc;I</strong>. Nếu ch&uacute;ng t&ocirc;i thay đổi Ch&iacute;nh s&aacute;ch bảo mật của m&igrave;nh, ch&uacute;ng t&ocirc;i sẽ th&ocirc;ng b&aacute;o cho bạn bao gồm cả th&ocirc;ng qua việc đăng tải những thay đổi đ&oacute; hoặc Ch&iacute;nh s&aacute;ch bảo mật sửa đổi tr&ecirc;n Nền tảng của ch&uacute;ng t&ocirc;i. Trong phạm vi ph&aacute;p luật cho ph&eacute;p, việc tiếp tục sử dụng c&aacute;c Dịch Vụ hoặc Nền Tảng, bao gồm giao dịch của bạn, được xem l&agrave; bạn đ&atilde; c&ocirc;ng nhận v&agrave; đồng &yacute; với c&aacute;c thay đổi trong Ch&iacute;nh s&aacute;ch bảo mật n&agrave;y.</span></span></span></span></p>\r\n\r\n<p style=\"text-align:justify\"><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><img alt=\"yes\" style=\"height:!important;width:!important;\" src=\"https://cdn.ckeditor.com/4.19.1/full/plugins/smiley/images/thumbs_up.png\" style=\"height:!important; width:!important\" title=\"yes\" />Ch&iacute;nh s&aacute;ch n&agrave;y &aacute;p dụng c&ugrave;ng với c&aacute;c th&ocirc;ng b&aacute;o, điều khoản hợp đồng, điều khoản chấp thuận kh&aacute;c &aacute;p dụng li&ecirc;n quan đến việc ch&uacute;ng t&ocirc;i thu thập, lưu trữ, sử dụng, tiết lộ v&agrave;/hoặc xử l&yacute; dữ liệu c&aacute; nh&acirc;n của bạn v&agrave; kh&ocirc;ng nhằm ghi đ&egrave; những th&ocirc;ng b&aacute;o hoặc c&aacute;c điều khoản đ&oacute; trừ khi ch&uacute;ng t&ocirc;i c&oacute; tuy&ecirc;n bố kh&aacute;c.</span></span></span></span></p>\r\n',1,'vn',1,''),(6,'Chương trình Afiiliate','2025-08-04',NULL,31,NULL,'',1,'vn',1,'');
