DROP TABLE IF EXISTS `sys_partner`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `sys_partner` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(255) DEFAULT NULL,
  `alias` varchar(255) DEFAULT NULL,
  `summary` text DEFAULT NULL,
  `content` text DEFAULT NULL,
  `source` varchar(100) DEFAULT NULL,
  `img` varchar(255) DEFAULT '',
  `img1` varchar(255) DEFAULT NULL,
  `title_img` varchar(255) DEFAULT NULL,
  `date_create` date DEFAULT NULL,
  `ctrl` bigint(5) DEFAULT 1,
  `lang` varchar(5) DEFAULT 'vn',
  `special_promotion` bigint(1) DEFAULT 0,
  `loiich` text DEFAULT NULL,
  `ainenhoc` text DEFAULT NULL,
  `giangvien` text DEFAULT NULL,
  `noidung` text DEFAULT NULL,
  `thongtin` text DEFAULT NULL,
  `uudai` text DEFAULT NULL,
  `pdf` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  FULLTEXT KEY `name` (`name`,`alias`,`summary`)
) ENGINE=MyISAM AUTO_INCREMENT=39 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci;
