INSERT INTO `sys_product` VALUES (15,48,'Tinh bột kháng UTRA NUTRI L68 (Hộp 5 gói)','tinh-bot-khang-utra-nutri-l68-hop-5-goi','Dinh dưỡng thay thế bữa ăn phụ lành mạnh.','<p style=\"text-align:justify\">Tinh bột kh&aacute;ng NUTRI - L68 l&agrave; sản phẩm d&ugrave;ng thay thế bữa ăn phụ h&agrave;ng ng&agrave;y, khi sử dụng theo liệu tr&igrave;nh từ 1 đến 6 th&aacute;ng, kết hợp với luyện tập thể dục thể thao, tuỳ theo từng thể trạng. NUTRI &ndash; L68 l&agrave; sản phẩm bổ sung dưỡng chất VITAMIN từ động v&agrave; thực vật.</p>\r\n\r\n<p style=\"text-align:justify\">Bữa ăn l&agrave;nh mạnh NUTRI L68 c&oacute; c&aacute;c th&agrave;nh phần: C&aacute;c loại hạt (Hạnh nh&acirc;n, hạt &Oacute;c ch&oacute;, Yến Mạch, hạt Điều, hạt Chia, hạt Sen, Gạo lứt, M&egrave; đen, &yacute; dĩ, Sa chi), đường Isomalt, Tinh bột kh&aacute;ng (từ bột chuối xanh), Nano Cucurnin, Muối hồng, Đ&ocirc;ng tr&ugrave;ng Hạ thảo (2.000 mcg/100g), Fucoidan (900 mcg/100g). Đối tượng sử dụng d&ugrave;ng cho người từ 6 tuổi trở l&ecirc;n. Nhờ c&oacute; chứa c&aacute;c th&agrave;nh phần tr&ecirc;n n&ecirc;n hỗ trợ rất tốt cho chức năng chuyển h&oacute;a.&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\"><u><strong>Lợi &iacute;ch sử dụng:</strong></u></p>\r\n\r\n<p style=\"text-align:justify\">Tốt cho hệ ti&ecirc;u h&oacute;a.<br />\r\nTinh bột kh&aacute;ng c&oacute; thể gi&uacute;p giảm nguy cơ mắc một số bệnh như ung thư đại tr&agrave;ng, trực tr&agrave;ng, c&aacute;c bệnh li&ecirc;n quan đến rối loạn chuyển h&oacute;a ...&nbsp;<br />\r\nTốt cho người tiểu đường v&agrave; tiền tiểu đường.<br />\r\nTốt cho những người huyết &aacute;p v&agrave; tim mạch.<br />\r\nBổ sung Vitamin v&agrave; kho&aacute;ng chất cho cơ thể.<br />\r\nThay thế bữa ăn phụ l&agrave;nh mạnh.</p>\r\n\r\n<p style=\"text-align:justify\"><strong><u>Đối tượng sử dụng:</u></strong></p>\r\n\r\n<p style=\"text-align:justify\">D&ugrave;ng cho trẻ em từ 6 tuổi trở l&ecirc;n v&agrave; người lớn.</p>\r\n','14EL61NT_Tinhbotkhang.jpg','',0,300000,0,0,'2025-10-22','vn',0,1,'','','Chăm sóc từ tâm - Nâng tầm cuộc sống','',NULL,'',NULL,0,'','','','',NULL,NULL,'',NULL,'','','','',1),(113,48,'Combo Thuận Phát 2','combo-thuan-phat-2','','<p>&nbsp;</p>\r\n\r\n<p><strong>COMBO THUẬN PH&Aacute;T 2 BAO GỒM<br />\r\n1 dung dịch xoa b&oacute;p QL Group 100ml: 1.150.000 VNĐ<br />\r\n1 hộp VEGAN MEALS: 1.150.000 VND<br />\r\n2 hộp GREEN: 2.500.000 VNĐ<br />\r\n1 hộp nội tiết tố nữ 2XH Plus</strong></p>\r\n','BEMI5EQR_combo2.png','',0,5650000,NULL,NULL,'2026-07-02','vn',1,1,'','','','',NULL,'',NULL,1,'','','','',NULL,NULL,'',NULL,'','','','',1),(14,48,'Dung dịch xoa bóp QL Group 100 ml','dung-dich-xoa-bop-ql-group-100-ml',' Hỗ trợ giảm đau nhức xương khớp, làm ấm cơ thể và tăng cường lưu thông máu. ','<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<p>Trong cuộc sống hiện đại, c&aacute;c bệnh l&yacute; về xương khớp, đau mỏi vai g&aacute;y hay t&ecirc; b&igrave; tay ch&acirc;n kh&ocirc;ng c&ograve;n l&agrave; nỗi lo của ri&ecirc;ng người cao tuổi m&agrave; đang ng&agrave;y c&agrave;ng trẻ h&oacute;a do th&oacute;i quen sinh hoạt v&agrave; đặc th&ugrave; c&ocirc;ng việc. Thấu hiểu điều đ&oacute;, C&ocirc;ng ty TNHH QL Group tự h&agrave;o mang đến sản phẩm Dung dịch xoa b&oacute;p Th&ocirc;ng Kinh Lạc (Th&acirc;n Khỏe T&acirc;m An). Đ&acirc;y l&agrave; người bạn đồng h&agrave;nh kh&ocirc;ng thể thiếu trong mọi tủ thuốc gia đ&igrave;nh, gi&uacute;p xua tan c&aacute;c cơn đau nhức v&agrave; mang lại cảm gi&aacute;c thư th&aacute;i, dễ chịu tức th&igrave;.</p>\r\n\r\n<p><strong>1. TỔNG QUAN VỀ SẢN PHẨM</strong></p>\r\n\r\n<p>Dung dịch xoa b&oacute;p Th&ocirc;ng Kinh Lạc QL Group l&agrave; sản phẩm chăm s&oacute;c sức khỏe cao cấp được nghi&ecirc;n cứu v&agrave; ph&aacute;t triển dựa tr&ecirc;n c&aacute;c b&agrave;i thuốc y học cổ truyền kết hợp với c&ocirc;ng nghệ b&agrave;o chế hiện đại. Với quy c&aacute;ch đ&oacute;ng chai 100ml tiện lợi c&ugrave;ng v&ograve;i xịt phun sương thẩm thấu nhanh, sản phẩm hỗ trợ đắc lực trong việc giảm đau, lưu th&ocirc;ng kh&iacute; huyết v&agrave; cải thiện sự linh hoạt của hệ cơ xương khớp.</p>\r\n\r\n<p><strong>2. TH&Agrave;NH PHẦN THẢO DƯỢC TỰ NHI&Ecirc;N TINH T&Uacute;Y</strong></p>\r\n\r\n<p>Sản phẩm được chiết xuất ho&agrave;n to&agrave;n từ 12 loại thảo dược tự nhi&ecirc;n qu&yacute; hiếm, l&agrave;nh t&iacute;nh v&agrave; c&oacute; dược t&iacute;nh cao trong việc điều trị c&aacute;c chứng đau nhức xương khớp v&agrave; th&ocirc;ng kinh hoạt lạc:</p>\r\n\r\n<table cellspacing=\"0\" class=\"Table\" style=\"border-collapse:collapse; border:none; margin-left:10px\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"background-color:#8c7254; border-bottom:1px solid #725d42; border-left:1px solid #725d42; border-right:1px solid #725d42; border-top:1px solid #725d42; height:43px; vertical-align:top; width:204px\">\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"color:white\">Thảo dược</span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#8c7254; border-bottom:1px solid #725d42; border-left:none; border-right:1px solid #725d42; border-top:1px solid #725d42; height:43px; vertical-align:top; width:476px\">\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"color:white\">C&ocirc;ng dụng ch&iacute;nh trong y học cổ truyền</span></strong></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:white; border-bottom:1px solid #e2dacd; border-left:1px solid #e2dacd; border-right:1px solid #e2dacd; border-top:none; height:63px; vertical-align:top; width:204px\">\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#8c7254\">Thi&ecirc;n Ni&ecirc;n Kiện</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:white; border-bottom:1px solid #e2dacd; border-left:none; border-right:1px solid #e2dacd; border-top:none; height:63px; vertical-align:top; width:476px\">\r\n			<p style=\"margin-left:10px; margin-right:17px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#2b241f\">Trừ phong thấp, cường g&acirc;n cốt; chuy&ecirc;n trị c&aacute;c chứng phong thấp t&ecirc; đau, nhức mỏi g&acirc;n cơ, đặc biệt tốt cho người cao tuổi.</span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#fbf9f4; border-bottom:1px solid #e2dacd; border-left:1px solid #e2dacd; border-right:1px solid #e2dacd; border-top:none; height:63px; vertical-align:top; width:204px\">\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#8c7254\">D&acirc;y Đau Xương</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#fbf9f4; border-bottom:1px solid #e2dacd; border-left:none; border-right:1px solid #e2dacd; border-top:none; height:63px; vertical-align:top; width:476px\">\r\n			<p style=\"margin-left:10px; margin-right:17px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#2b241f\">Thư c&acirc;n hoạt lạc, khu phong trừ thấp; d&ugrave;ng điều trị triệu chứng của bệnh t&ecirc; bại, đau xương khớp, đau vai g&aacute;y.</span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:white; border-bottom:1px solid #e2dacd; border-left:1px solid #e2dacd; border-right:1px solid #e2dacd; border-top:none; height:63px; vertical-align:top; width:204px\">\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#8c7254\">Độc Hoạt</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:white; border-bottom:1px solid #e2dacd; border-left:none; border-right:1px solid #e2dacd; border-top:none; height:63px; vertical-align:top; width:476px\">\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#2b241f\">Khử phong, thắng thấp, chỉ thống (giảm đau); c&oacute; t&aacute;c dụng tốt với c&aacute;c cơn đau từ thắt lưng trở xuống.</span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#fbf9f4; border-bottom:1px solid #e2dacd; border-left:1px solid #e2dacd; border-right:1px solid #e2dacd; border-top:none; height:63px; vertical-align:top; width:204px\">\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#8c7254\">Huyết Gi&aacute;c</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#fbf9f4; border-bottom:1px solid #e2dacd; border-left:none; border-right:1px solid #e2dacd; border-top:none; height:63px; vertical-align:top; width:476px\">\r\n			<p style=\"margin-left:10px; margin-right:17px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#2b241f\">Hoạt huyết, chỉ huyết, t&aacute;n ứ, ti&ecirc;u thũng; đặc trị c&aacute;c vết bầm t&iacute;m, sưng tấy do chấn thương hoặc va đập.</span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:white; border-bottom:1px solid #e2dacd; border-left:1px solid #e2dacd; border-right:1px solid #e2dacd; border-top:none; height:63px; vertical-align:top; width:204px\">\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#8c7254\">Đại Hồi &amp; &Ocirc; Đầu</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:white; border-bottom:1px solid #e2dacd; border-left:none; border-right:1px solid #e2dacd; border-top:none; height:63px; vertical-align:top; width:476px\">\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#2b241f\">&Ocirc;n trung, t&aacute;n h&agrave;n, chỉ thống; gi&uacute;p l&agrave;m ấm s&acirc;u c&aacute;c đường kinh mạch, giảm đau mạnh mẽ do kh&iacute; huyết ứ trệ.</span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<table cellspacing=\"0\" class=\"Table\" style=\"border-collapse:collapse; border:none; margin-left:10px\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"background-color:#fbf9f4; border-bottom:1px solid #e2dacd; border-left:1px solid #e2dacd; border-right:1px solid #e2dacd; border-top:1px solid #725d42; height:63px; vertical-align:top; width:204px\">\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#8c7254\">M&atilde; Tiền &amp; Địa Liền</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#fbf9f4; border-bottom:1px solid #e2dacd; border-left:none; border-right:1px solid #e2dacd; border-top:1px solid #725d42; height:63px; vertical-align:top; width:476px\">\r\n			<p style=\"margin-left:10px; margin-right:17px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#2b241f\">Th&ocirc;ng lạc chỉ thống, trừ t&agrave; kh&iacute;, ti&ecirc;u thũng; hỗ trợ giảm c&aacute;c cơn đau khớp m&atilde;n t&iacute;nh v&agrave; t&igrave;nh trạng t&ecirc; b&igrave;.</span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:white; border-bottom:1px solid #e2dacd; border-left:1px solid #e2dacd; border-right:1px solid #e2dacd; border-top:none; height:63px; vertical-align:top; width:204px\">\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#8c7254\">Ph&ograve;ng Phong &amp; Ngải Cứu</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:white; border-bottom:1px solid #e2dacd; border-left:none; border-right:1px solid #e2dacd; border-top:none; height:63px; vertical-align:top; width:476px\">\r\n			<p style=\"margin-left:10px; margin-right:17px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#2b241f\">Trừ phong giải biểu, t&aacute;n h&agrave;n, điều h&ograve;a kh&iacute; huyết; gi&uacute;p thư gi&atilde;n cơ bắp, giảm co thắt cơ v&agrave; chống vi&ecirc;m nhẹ ngo&agrave;i da.</span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#fbf9f4; border-bottom:1px solid #e2dacd; border-left:1px solid #e2dacd; border-right:1px solid #e2dacd; border-top:none; height:63px; vertical-align:top; width:204px\">\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#8c7254\">Quế Nhục &amp; Hạt Ti&ecirc;u</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#fbf9f4; border-bottom:1px solid #e2dacd; border-left:none; border-right:1px solid #e2dacd; border-top:none; height:63px; vertical-align:top; width:476px\">\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#2b241f\">Trợ dương, t&aacute;n h&agrave;n, &ocirc;n th&ocirc;ng kinh lạc; tạo nhiệt lượng tự nhi&ecirc;n bền bỉ l&agrave;m ấm cơ thể, tăng cường tuần ho&agrave;n m&aacute;u ngoại vi.</span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p><strong>3. C&Ocirc;NG DỤNG VƯỢT TRỘI</strong></p>\r\n\r\n<p>Sự kết hợp ho&agrave;n hảo của c&aacute;c vị thảo dược mang lại hiệu quả đa năng, t&aacute;c động s&acirc;u v&agrave;o c&aacute;c v&ugrave;ng tổn thương:</p>\r\n\r\n<p>&bull;&nbsp;&nbsp; &nbsp;Khu phong, hoạt lạc v&agrave; lưu th&ocirc;ng kh&iacute; huyết: K&iacute;ch th&iacute;ch tuần ho&agrave;n m&aacute;u tại v&ugrave;ng được xoa b&oacute;p, gi&uacute;p l&agrave;m ấm cơ thể nhanh ch&oacute;ng, giải ph&oacute;ng c&aacute;c điểm kinh lạc bị tắc nghẽn, tạo cảm gi&aacute;c thư gi&atilde;n v&agrave; dễ chịu s&acirc;u.<br />\r\n&bull;&nbsp;&nbsp; &nbsp;Giảm đau cơ v&agrave; xương khớp tốc h&agrave;nh: Hỗ trợ giảm nhanh c&aacute;c triệu chứng đau mỏi cổ, vai, g&aacute;y, đau lưng, c&aacute;nh tay, cổ tay do ngồi sai tư thế hoặc l&agrave;m việc qu&aacute; sức.<br />\r\n&bull;&nbsp;&nbsp; &nbsp;Hỗ trợ điều trị chấn thương cơ học: Giảm sưng ph&ugrave; nề, tan nhanh c&aacute;c vết bầm t&iacute;m, hỗ trợ phục hồi hiệu quả trong c&aacute;c trường hợp bong g&acirc;n, căng cơ do hoạt động thể thao hoặc va chạm.</p>\r\n\r\n<p><strong>4. ĐỐI TƯỢNG SỬ DỤNG ĐA DẠNG</strong></p>\r\n\r\n<p>Sản phẩm ph&ugrave; hợp với nhiều nh&oacute;m đối tượng nhờ t&iacute;nh an to&agrave;n v&agrave; hiệu quả đa chức năng:</p>\r\n\r\n<p>1.&nbsp;&nbsp; &nbsp;Người l&agrave;m việc văn ph&ograve;ng, lao động nặng: Thường xuy&ecirc;n bị đau mỏi cổ, vai, g&aacute;y, t&ecirc; cứng c&aacute;nh tay, đau mỏi thắt lưng.<br />\r\n2.&nbsp;&nbsp; &nbsp;Người mắc bệnh l&yacute; xương khớp m&atilde;n t&iacute;nh: Người bị tho&aacute;t vị đĩa đệm, gai cột sống, tho&aacute;i h&oacute;a khớp, t&ecirc; b&igrave; tay ch&acirc;n, đau d&acirc;y thần kinh m&atilde;n t&iacute;nh.<br />\r\n3.&nbsp;&nbsp; &nbsp;Người bị chấn thương vận động: Người bị sưng ph&ugrave; nề, chấn thương cơ khớp, bong g&acirc;n, bầm t&iacute;m do va đập, chơi thể thao.<br />\r\n4.&nbsp;&nbsp; &nbsp;Hỗ trợ bảo vệ sức khỏe cả gia đ&igrave;nh: D&ugrave;ng để xoa b&oacute;p giảm ho, l&agrave;m ấm cơ thể khi bị cảm c&uacute;m, vi&ecirc;m mũi do lạnh. Đặc biệt, trẻ em từ 3 tuổi trở l&ecirc;n bị muỗi đốt, c&ocirc;n tr&ugrave;ng cắn g&acirc;y mẩn ngứa ngo&agrave;i da đều c&oacute; thể sử dụng để l&agrave;m dịu da nhanh ch&oacute;ng.</p>\r\n\r\n<p><strong>5.&nbsp; HƯỚNG DẪN SỬ DỤNG ĐỂ ĐẠT HIỆU QUẢ CAO NHẤT</strong></p>\r\n\r\n<p>Để c&aacute;c tinh chất thảo dược thẩm thấu s&acirc;u v&agrave; ph&aacute;t huy tối đa c&ocirc;ng dụng, người d&ugrave;ng n&ecirc;n tu&acirc;n thủ c&aacute;c bước sau:</p>\r\n\r\n<p>&bull;&nbsp;&nbsp; &nbsp;Bước 1: Lắc đều chai trước khi sử dụng. Xịt trực tiếp dung dịch l&ecirc;n v&ugrave;ng da bị đau nhức hoặc v&ugrave;ng cần t&aacute;c động (ch&uacute; &yacute; tr&aacute;nh v&ugrave;ng mắt v&agrave; miệng).</p>\r\n\r\n<p>&bull;&nbsp;&nbsp; &nbsp;Bước 2: D&ugrave;ng tay xoa b&oacute;p, day ấn nhẹ nh&agrave;ng từ 10 &ndash; 15 ph&uacute;t. Việc massage n&agrave;y gi&uacute;p mạch m&aacute;u gi&atilde;n nở, hỗ trợ c&aacute;c hoạt chất từ Thi&ecirc;n Ni&ecirc;n Kiện, D&acirc;y Đau Xương... thẩm thấu nhanh v&agrave; s&acirc;u v&agrave;o tận sụn khớp, m&ocirc; cơ.<br />\r\n&bull;&nbsp;&nbsp; &nbsp;Bước 3: C&oacute; thể sử dụng từ 2 &ndash; 3 lần mỗi ng&agrave;y hoặc bất cứ khi n&agrave;o xuất hiện cơn đau nhức.</p>\r\n\r\n<p><strong>CH&Uacute; &Yacute; QUAN TRỌNG KHI SỬ DỤNG:</strong></p>\r\n\r\n<p>&bull;&nbsp;&nbsp; &nbsp;Sản phẩm d&ugrave;ng ngo&agrave;i da, tuyệt đối KH&Ocirc;NG ĐƯỢC UỐNG.<br />\r\n&bull;&nbsp;&nbsp; &nbsp;Kh&ocirc;ng d&ugrave;ng cho trẻ em dưới 12 th&aacute;ng tuổi.<br />\r\n&bull;&nbsp;&nbsp; &nbsp;Kh&ocirc;ng xịt trực tiếp l&ecirc;n c&aacute;c vết thương hở, v&ugrave;ng da bị lo&eacute;t hoặc tổn thương r&aacute;ch da.<br />\r\n&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n','BEMJDK11_1121.png','',0,1150000,0,0,'2026-07-01','vn',1,1,'','','Thân khỏe - Tâm an','',NULL,'',NULL,1,'','','','',NULL,NULL,'',NULL,'','','','',1),(71,48,'VEGAN MEALS','vegan-meals','Giải pháp vàng cân bằng chuyển hóa và khơi nguồn sức khỏe toàn diện.','<p><img alt=\"\" style=\"height:!important;width:!important;\" src=\"/image/Vegan.jpg\" style=\"height:!important; width:!important\" /><br />\r\nTrong nhịp sống hiện đại hối hả, cơ thể ch&uacute;ng ta thường xuy&ecirc;n phải đối mặt với &aacute;p lực từ &ocirc; nhiễm m&ocirc;i trường, thực phẩm c&ocirc;ng nghiệp v&agrave; th&oacute;i quen sinh hoạt thiếu khoa học. Đ&acirc;y ch&iacute;nh l&agrave; những nguy&ecirc;n nh&acirc;n cốt l&otilde;i dẫn đến t&igrave;nh trạng rối loạn chuyển h&oacute;a &ndash; nguồn gốc của c&aacute;c căn bệnh thời đại như b&eacute;o ph&igrave;, tiểu đường, mỡ m&aacute;u cao v&agrave; tim mạch. Thấu hiểu s&acirc;u sắc điều đ&oacute;, C&ocirc;ng ty CP TM Quốc tế Thuận Ph&aacute;t đ&atilde; nghi&ecirc;n cứu v&agrave; cho ra đời sản phẩm thực dưỡng cao cấp Vegan Meals &ndash; một giải ph&aacute;p dinh dưỡng to&agrave;n diện, hỗ trợ cải thiện &amp; c&acirc;n bằng chuyển h&oacute;a một c&aacute;ch tự nhi&ecirc;n nhất.</p>\r\n\r\n<p>SỰ KẾT HỢP TINH TẾ GIỮA THỰC DƯỠNG OHSAWA V&Agrave; KHOA HỌC HARVARD</p>\r\n\r\n<p>Vegan Meals kh&ocirc;ng chỉ đơn thuần l&agrave; một loại bột ngũ cốc th&ocirc;ng thường, m&agrave; l&agrave; một c&ocirc;ng thức đột ph&aacute; kết hợp h&agrave;i h&ograve;a giữa triết l&yacute; Thực dưỡng Ohsawa phương Đ&ocirc;ng v&agrave; Ti&ecirc;u chuẩn dinh dưỡng to&agrave;n phần theo khoa học Harvard phương T&acirc;y:</p>\r\n\r\n<p>&bull;&nbsp;&nbsp; &nbsp;Triết l&yacute; Ohsawa (C&acirc;n bằng &Acirc;m - Dương): C&aacute;c th&agrave;nh phần trong Vegan Meals được chọn lọc v&agrave; phối trộn nghi&ecirc;m ngặt theo t&iacute;nh chất &Acirc;m - Dương của thực phẩm, gi&uacute;p cơ thể thiết lập trạng th&aacute;i qu&acirc;n b&igrave;nh, n&acirc;ng cao sinh kh&iacute; v&agrave; tăng cường khả năng tự chữa l&agrave;nh từ b&ecirc;n trong.</p>\r\n\r\n<p>&bull;&nbsp;&nbsp; &nbsp;Ti&ecirc;u chuẩn Dinh dưỡng Harvard (To&agrave;n phần &amp; Tự nhi&ecirc;n): Sản phẩm giữ trọn vẹn gi&aacute; trị dinh dưỡng của c&aacute;c nguy&ecirc;n liệu th&ocirc;, cung cấp tỷ lệ v&agrave;ng giữa c&aacute;c nh&oacute;m chất: đạm thực vật sạch, chất xơ h&ograve;a tan, chất b&eacute;o l&agrave;nh mạnh v&agrave; c&aacute;c vi chất thiết yếu để tối ưu h&oacute;a năng lượng tế b&agrave;o.</p>\r\n\r\n<p>TH&Agrave;NH PHẦN V&Agrave; C&Ocirc;NG DỤNG CHI TIẾT CỦA 12 NGUY&Ecirc;N LIỆU V&Agrave;NG</p>\r\n\r\n<table align=\"center\" cellspacing=\"0\" class=\"Table\" style=\"border-collapse:collapse\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"background-color:#2e7d32; vertical-align:top; width:201px\">\r\n			<p style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><strong><span style=\"color:black\">Th&agrave;nh phần</span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#2e7d32; vertical-align:top; width:201px\">\r\n			<p style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><strong><span style=\"color:black\">C&ocirc;ng dụng khoa học</span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#2e7d32; vertical-align:top; width:201px\">\r\n			<p style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><strong><span style=\"color:black\">Vai tr&ograve; thực dưỡng</span></strong></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">1. Bột chuối xanh</span></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">Gi&agrave;u tinh bột kh&aacute;ng (resistant starch) nu&ocirc;i dưỡng lợi khuẩn, hỗ trợ ti&ecirc;u h&oacute;a, giảm c&acirc;n, ổn định đường huyết, cholesterol v&agrave; huyết &aacute;p.</span></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">Trung h&ograve;a &Acirc;m &ndash; Dương, nhuận tr&agrave;ng, duy tr&igrave; năng lượng bền vững.</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#f1f8e9; vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">2. Bột yến mạch</span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f1f8e9; vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">Cung cấp beta-glucan giảm cholesterol xấu (LDL), bảo vệ tim mạch, gi&agrave;u chất xơ h&ograve;a tan tạo cảm gi&aacute;c no l&acirc;u v&agrave; tăng sức bền.</span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f1f8e9; vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">T&iacute;nh Dương nhẹ, ổn định năng lượng cho lối sống hiện đại.</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">3. Bột đậu g&agrave;</span></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">Nguồn protein thực vật ho&agrave;n chỉnh gi&agrave;u axit amin, folate, sắt, magie gi&uacute;p bổ m&aacute;u, kiểm so&aacute;t đường huyết rất tốt cho người tiểu đường.</span></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">C&acirc;n bằng năng lượng, bổ tỳ vị, dưỡng kh&iacute; huyết.</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#f1f8e9; vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">4. Bột &yacute; dĩ (Bo bo)</span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f1f8e9; vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">Thanh lọc cơ thể, lợi tiểu, giảm sưng ph&ugrave;, tăng cường miễn dịch, gi&uacute;p l&agrave;m mịn v&agrave; s&aacute;ng da r&otilde; rệt.</span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f1f8e9; vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">&Acirc;m trung h&ograve;a, gi&uacute;p cơ thể thanh nhẹ, giải độc nhẹ nh&agrave;ng.</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">5. Bột hạt sen</span></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">An thần, ngủ ngon, giảm stress, ổn định hệ thần kinh, gi&agrave;u protein v&agrave; kali tốt cho tim mạch, tr&iacute; n&atilde;o.</span></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">T&iacute;nh &Acirc;m m&aacute;t, điều h&ograve;a cơ thể, c&acirc;n bằng thần kinh.</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#f1f8e9; vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">6. Bột hạnh nh&acirc;n</span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f1f8e9; vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">Cung cấp Omega-9, Omega-6, Vitamin E v&agrave; Canxi gi&uacute;p chống oxy h&oacute;a, trẻ h&oacute;a tế b&agrave;o, bảo vệ tim mạch, da v&agrave; xương.</span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f1f8e9; vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">Dương t&iacute;nh, bổ dưỡng nhẹ, l&agrave;m ấm cơ thể.</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">7. Bột sắn d&acirc;y</span></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">Giải nhiệt, hạ đường huyết, l&agrave;m m&aacute;t gan, hỗ trợ hệ ti&ecirc;u h&oacute;a, tuần ho&agrave;n, giảm nhanh mệt mỏi v&agrave; t&aacute;o b&oacute;n.</span></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">&Acirc;m t&iacute;nh, qu&acirc;n b&igrave;nh với c&aacute;c thực phẩm Dương, h&agrave;i h&ograve;a cơ thể.</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#f1f8e9; vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">8. Bột vừng</span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f1f8e9; vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">Gi&agrave;u Canxi, Magie, Kẽm, Vitamin E gi&uacute;p xương chắc khỏe, t&oacute;c mượt, da đẹp, nhuận tr&agrave;ng v&agrave; giảm mỡ m&aacute;u.</span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f1f8e9; vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">C&acirc;n bằng &Acirc;m Dương, dưỡng huyết, bổ thận, mềm gan.</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">9. Chiết xuất cỏ ngọt</span></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">Tạo vị ngọt thanh tự nhi&ecirc;n, ho&agrave;n to&agrave;n kh&ocirc;ng chứa calo, kh&ocirc;ng l&agrave;m tăng chỉ số đường huyết.</span></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">Trung t&iacute;nh, giữ sự thanh khiết cho sản phẩm.</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#f1f8e9; vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">10. Muối hồng Himalaya</span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f1f8e9; vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">Cung cấp hơn 80 kho&aacute;ng chất vi lượng, c&acirc;n bằng điện giải, tuần ho&agrave;n m&aacute;u, trung h&ograve;a axit nhờ t&iacute;nh kiềm nhẹ.</span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f1f8e9; vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">Dương mạnh, điều h&ograve;a &Acirc;m Dương, tăng cường sinh kh&iacute;.</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">11. Chiết xuất tảo n&acirc;u</span></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">Gi&agrave;u Fucoidan v&agrave; Iodine gi&uacute;p tăng miễn dịch mạnh mẽ, chống oxy h&oacute;a, cải thiện tuyến gi&aacute;p v&agrave; giảm mỡ nội tạng.</span></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">&Acirc;m - Dương c&acirc;n bằng, thanh lọc, nu&ocirc;i dưỡng tế b&agrave;o s&acirc;u.</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#f1f8e9; vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">12. Vitamin K2 (MK-7)</span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f1f8e9; vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">Nguồn gốc tự nhi&ecirc;n với thời gian b&aacute;n hủy d&agrave;i, gi&uacute;p định hướng Canxi hấp thu thẳng v&agrave;o xương/răng, tr&aacute;nh v&ocirc;i h&oacute;a mạch m&aacute;u.</span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f1f8e9; vertical-align:top; width:201px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">Bổ trợ chuyển h&oacute;a năng lượng, c&acirc;n bằng nội m&ocirc;i cơ thể.</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>GI&Aacute; TRỊ DINH DƯỠNG TO&Agrave;N DIỆN (TR&Ecirc;N 100G)</p>\r\n\r\n<table align=\"center\" cellspacing=\"0\" class=\"Table\" style=\"border-collapse:collapse\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"vertical-align:top; width:150px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><strong><span style=\"color:black\">Năng lượng</span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:150px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">369,04 Kcal</span></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:150px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><strong><span style=\"color:black\">Đường tổng số</span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:150px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">2,77 g</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"vertical-align:top; width:150px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><strong><span style=\"color:black\">Chất đạm (Protein)</span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:150px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">13,27 g</span></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:150px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><strong><span style=\"color:black\">Natri</span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:150px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">34,93 mg</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"vertical-align:top; width:150px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><strong><span style=\"color:black\">Chất b&eacute;o (Lipid)</span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:150px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">9,12 g</span></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:150px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><strong><span style=\"color:black\">Vitamin K2 (MK-7)</span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:150px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">13,3 &mu;g</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"vertical-align:top; width:150px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><strong><span style=\"color:black\">Carbohydrat</span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:150px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:black\">58,47 g</span></span></span></p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:150px\">\r\n			<p>&nbsp;</p>\r\n			</td>\r\n			<td style=\"vertical-align:top; width:150px\">\r\n			<p>&nbsp;</p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p>LỢI &Iacute;CH SỨC KHỎE VƯỢT TRỘI CỦA VEGAN MEALS</p>\r\n\r\n<p>&bull;&nbsp;&nbsp; &nbsp;Hỗ trợ ổn định đường huyết: Th&iacute;ch hợp cho người tiểu đường v&agrave; tiền tiểu đường.<br />\r\n&bull;&nbsp;&nbsp; &nbsp;Hỗ trợ giảm mỡ m&aacute;u: Đ&aacute;nh tan c&aacute;c nguy cơ xơ vữa động mạch, bảo vệ tr&aacute;i tim khỏe mạnh.<br />\r\n&bull;&nbsp;&nbsp; &nbsp;Hỗ trợ thanh lọc cơ thể: Đ&agrave;o thải độc tố, m&aacute;t gan, lợi tiểu nhờ cơ chế tự nhi&ecirc;n.<br />\r\n&bull;&nbsp;&nbsp; &nbsp;Hỗ trợ tăng cường chuyển h&oacute;a: K&iacute;ch th&iacute;ch năng lượng tế b&agrave;o, đẩy l&ugrave;i hội chứng rối loạn chuyển h&oacute;a.<br />\r\n&bull;&nbsp;&nbsp; &nbsp;Hỗ trợ duy tr&igrave; c&acirc;n nặng hợp l&yacute;: Gi&uacute;p giữ v&oacute;c d&aacute;ng thon gọn một c&aacute;ch khoa học m&agrave; kh&ocirc;ng mệt mỏi.</p>\r\n\r\n<p>ĐỐI TƯỢNG SỬ DỤNG L&Yacute; TƯỞNG</p>\r\n\r\n<p>Sản phẩm đặc biệt ph&ugrave; hợp cho người tr&ecirc;n 18 tuổi thuộc c&aacute;c nh&oacute;m đối tượng sau:<br />\r\n&bull;&nbsp;&nbsp; &nbsp;Người thừa c&acirc;n, b&eacute;o ph&igrave; muốn t&igrave;m lại v&oacute;c d&aacute;ng c&acirc;n đối.<br />\r\n&bull;&nbsp;&nbsp; &nbsp;Người đang gặp c&aacute;c t&igrave;nh trạng rối loạn chuyển h&oacute;a.<br />\r\n&bull;&nbsp;&nbsp; &nbsp;Người bị tiểu đường, mỡ m&aacute;u cao, huyết &aacute;p kh&ocirc;ng ổn định.<br />\r\n&bull;&nbsp;&nbsp; &nbsp;Người theo đuổi lối sống ăn chay, ăn ki&ecirc;ng khoa học, l&agrave;nh mạnh.</p>\r\n\r\n<p>HƯỚNG DẪN SỬ DỤNG&nbsp;</p>\r\n\r\n<p>Để đạt hiệu quả tối ưu, Sếp n&ecirc;n duy tr&igrave; th&oacute;i quen sử dụng Vegan Meals mỗi ng&agrave;y theo c&aacute;c bước:<br />\r\n&bull;&nbsp;&nbsp; &nbsp;Bước 1: Pha 1 g&oacute;i (tương đương 20g) với 100ml nước ấm (nhiệt độ khoảng 60 &ndash; 70&deg;C).<br />\r\n&bull;&nbsp;&nbsp; &nbsp;Bước 2: Khuấy đều cho đến khi bột h&ograve;a tan ho&agrave;n to&agrave;n.<br />\r\n&bull;&nbsp;&nbsp; &nbsp;Bước 3: Thưởng thức ly hương vị thơm ngon, thanh khiết. Sử dụng đều đặn ng&agrave;y 2-3 lần.</p>\r\n\r\n<p>CAM KẾT CHẤT LƯỢNG&nbsp;</p>\r\n\r\n<p>Vegan Meals cam kết ti&ecirc;u chuẩn 4 KH&Ocirc;NG v&igrave; sức khỏe cộng đồng: Kh&ocirc;ng chất bảo quản - Kh&ocirc;ng tạo m&agrave;u - Kh&ocirc;ng tạo vị - Kh&ocirc;ng tạo hương. Sản phẩm được sản xuất theo quy tr&igrave;nh hiện đại, kiểm định an to&agrave;n chất lượng nghi&ecirc;m ngặt với 100% nguy&ecirc;n liệu thực dưỡng cao cấp thực sự thuần chay.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<div class=\"youtube\" style=\"text-align:center\">\r\n<div class=\"youtube\" style=\"text-align:center\"><div class=\"youtube\" style=\"text-align:center\"><iframe frameborder=\"0\" height=\"377\" style=\"height:!important;width:!important;\" src=\"https://www.youtube.com/embed/Q4xD7Y4mzyI\" style=\"height:!important;width:!important;\" title=\"VEGAN MEALS\" width=\"670\"></iframe></div></div>\r\n</div>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n','BCKBK3JU_veganmeals.jpg','',0,1150000,NULL,NULL,'2026-07-01','vn',1,1,'','','Thực phẩm bổ xung','',NULL,'',NULL,1,'','','','',NULL,NULL,'',NULL,'','','','',1),(103,48,'Bữa ăn chay GREEN','bua-an-chay-green','Công thức đột phá từ tự nhiên và công nghệ cao.','<p style=\"text-align:justify\"><img alt=\"\" style=\"height:!important;width:!important;\" src=\"/image/Green1.jpg\" style=\"height:!important; width:!important\" /></p>\r\n\r\n<p style=\"text-align:justify\"><br />\r\nĐiểm nhấn vượt trội l&agrave;m n&ecirc;n thương hiệu HANA ch&iacute;nh l&agrave; sự kết hợp của chuỗi nguy&ecirc;n liệu tự nhi&ecirc;n si&ecirc;u dinh dưỡng được tuyển chọn khắt khe, &aacute;p dụng c&ocirc;ng nghệ si&ecirc;u hấp thu từ tế b&agrave;o gi&uacute;p giải ph&oacute;ng tối đa dưỡng chất:</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Tỏi đen &amp; Nghệ Curcumin: Hỗ trợ chống oxy h&oacute;a mạnh mẽ, bảo vệ th&agrave;nh mạch v&agrave; ngăn ngừa xơ vữa động mạch.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Đ&ocirc;ng Tr&ugrave;ng Hạ Thảo: Thảo dược qu&yacute; hiếm gi&uacute;p tăng cường hệ miễn dịch, bổ sung năng lượng, hỗ trợ tuần ho&agrave;n m&aacute;u v&agrave; n&acirc;ng cao sức khỏe tổng thể.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Hạnh Nh&acirc;n &amp; Vừng M&egrave;: Cung cấp nguồn chất b&eacute;o l&agrave;nh mạnh (Omega-3, 6), vitamin E v&agrave; kho&aacute;ng chất thiết yếu gi&uacute;p l&agrave;m sạch mạch m&aacute;u v&agrave; kiểm so&aacute;t cholesterol.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Muối Hồng: Gi&uacute;p c&acirc;n bằng điện giải, hỗ trợ duy tr&igrave; huyết &aacute;p ổn định v&agrave; thanh lọc cơ thể.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Chuỗi Xanh &amp; Bồng Yến Mạch: Mang lại bữa ăn chay l&agrave;nh mạnh, gi&agrave;u chất xơ h&ograve;a tan, hỗ trợ hệ ti&ecirc;u h&oacute;a v&agrave; tối ưu h&oacute;a qu&aacute; tr&igrave;nh chuyển h&oacute;a năng lượng, ngăn ngừa rối loạn chuyển h&oacute;a to&agrave;n diện.</p>\r\n\r\n<p style=\"text-align:justify\">&nbsp;<strong>C&ocirc;ng Dụng Vượt Trội Của HANA Trong Việc Ph&ograve;ng Chống Tai Biến Đột Quỵ</strong></p>\r\n\r\n<p style=\"text-align:justify\">Khi sử dụng đều đặn mỗi ng&agrave;y, HANA mang lại những lợi &iacute;ch r&otilde; rệt cho sức khỏe:</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Hỗ trợ ph&ograve;ng chống tai biến đột quỵ từ sớm: Gi&uacute;p hoạt huyết, hỗ trợ lưu th&ocirc;ng m&aacute;u đều đặn đến c&aacute;c cơ quan, đặc biệt l&agrave; n&atilde;o bộ, giảm thiểu nguy cơ h&igrave;nh th&agrave;nh cục m&aacute;u đ&ocirc;ng &ndash; nguy&ecirc;n nh&acirc;n ch&iacute;nh dẫn đến đột quỵ.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Tăng cường sức khỏe tim mạch v&agrave; hệ tuần ho&agrave;n: Bảo vệ tế b&agrave;o cơ tim, hỗ trợ duy tr&igrave; huyết &aacute;p v&agrave; tim mạch ổn định, giảm &aacute;p lực l&ecirc;n l&ograve;ng mạch.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Hỗ trợ xử l&yacute; rối loạn chuyển h&oacute;a: Đ&oacute;ng vai tr&ograve; l&agrave; bữa ăn dinh dưỡng to&agrave;n diện, hỗ trợ t&iacute;ch cực cho những người đang gặp c&aacute;c hội chứng rối loạn chuyển h&oacute;a, giảm mỡ m&aacute;u xấu.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;N&acirc;ng cao sức đề kh&aacute;ng v&agrave; thể trạng tổng thể: Bổ sung c&aacute;c vi chất, enzyme tự nhi&ecirc;n gi&uacute;p cơ thể phục hồi nhanh ch&oacute;ng sau những giờ l&agrave;m việc căng thẳng, đẩy l&ugrave;i mệt mỏi.</p>\r\n\r\n<p style=\"text-align:justify\"><strong>Đối Tượng Sử Dụng Ph&ugrave; Hợp.</strong></p>\r\n\r\n<p style=\"text-align:justify\">Sản phẩm dinh dưỡng HANA được thiết kế tiện lợi, hương vị thơm ngon dễ uống, ph&ugrave; hợp với đa dạng đối tượng:</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp; Người trưởng th&agrave;nh bận rộn, người thường xuy&ecirc;n l&agrave;m việc tr&iacute; &oacute;c căng thẳng, chịu nhiều &aacute;p lực dẫn đến mệt mỏi, suy nhược.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp; Người cao tuổi, người c&oacute; tiền sử hoặc nguy cơ mắc c&aacute;c bệnh về tim mạch, huyết &aacute;p, mỡ m&aacute;u hoặc tuần ho&agrave;n m&aacute;u k&eacute;m.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp; Người c&oacute; lối sống &iacute;t vận động, người c&oacute; nhu cầu bổ sung dinh dưỡng xanh sạch để duy tr&igrave; v&oacute;c d&aacute;ng v&agrave; bảo vệ sức khỏe chủ động.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp; Những người mong muốn t&igrave;m kiếm một bữa ăn chay thực dưỡng l&agrave;nh mạnh, an to&agrave;n v&agrave; đầy đủ vi chất.</p>\r\n\r\n<p style=\"text-align:justify\"><strong>Bảo Chứng Chất Lượng &amp; Uy T&iacute;n Thương Hiệu HANA.</strong></p>\r\n\r\n<p style=\"text-align:justify\">Kh&aacute;ch h&agrave;ng ho&agrave;n to&agrave;n c&oacute; thể an t&acirc;m tuyệt đối khi lựa chọn HANA bởi sản phẩm sở hữu những bảo chứng chất lượng vững chắc từ c&aacute;c cơ quan uy t&iacute;n:</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Nh&agrave; m&aacute;y chuẩn GMP: Quy tr&igrave;nh sản xuất kh&eacute;p k&iacute;n, hiện đại đạt ti&ecirc;u chuẩn quốc tế nghi&ecirc;m ngặt.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Đạt TOP 100 Sản phẩm, Dịch vụ tốt nhất cho Gia đ&igrave;nh v&agrave; Trẻ em: Vinh dự lọt v&agrave;o nh&oacute;m sản phẩm dịch vụ uy t&iacute;n được người ti&ecirc;u d&ugrave;ng đ&aacute;nh gi&aacute; cao, bảo chứng cho sự an to&agrave;n v&agrave; hiệu quả thiết thực.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Hội đồng chuy&ecirc;n gia đầu ng&agrave;nh: Được nghi&ecirc;n cứu, cố vấn chuy&ecirc;n m&ocirc;n v&agrave; ph&aacute;t triển bởi đội ngũ chuy&ecirc;n gia, c&aacute;c nh&agrave; khoa học c&oacute; t&acirc;m, c&oacute; tầm, t&agrave;i năng chuy&ecirc;n s&acirc;u về lĩnh vực y dược v&agrave; sức khỏe. Trong đ&oacute; c&oacute; sự đồng h&agrave;nh của Đại t&aacute; Qu&acirc;n y - Gi&aacute;o sư - B&aacute;c sĩ Phạm Vinh Quang (Nguy&ecirc;n B&aacute;c sĩ Bệnh viện Qu&acirc;n y 103), mang lại sự tin cậy tuyệt đối về mặt khoa học.</p>\r\n\r\n<p style=\"text-align:justify\"><strong>Hướng Dẫn Sử Dụng Để Đạt Hiệu Quả Tốt Nhất.</strong></p>\r\n\r\n<p style=\"text-align:justify\">Để HANA ph&aacute;t huy tối đa c&ocirc;ng dụng hỗ trợ ph&ograve;ng chống tai biến v&agrave; n&acirc;ng cao sức khỏe, người d&ugrave;ng n&ecirc;n duy tr&igrave; th&oacute;i quen sử dụng đều đặn h&agrave;ng ng&agrave;y theo hướng dẫn:</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp; Sử dụng l&agrave;m bữa ăn s&aacute;ng tiện lợi hoặc bữa ăn phụ xế chiều (khoảng 1-2 ly mỗi ng&agrave;y). Pha bột với nước ấm, khuấy đều v&agrave; thưởng thức khi c&ograve;n ấm.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp; Kết hợp c&ugrave;ng chế độ ăn uống khoa học (giảm mặn, giảm dầu mỡ động vật, tăng cường rau xanh) v&agrave; uống đủ nước.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp; Duy tr&igrave; chế độ vận động hợp l&yacute; (đi bộ, tập thể dục nhẹ nh&agrave;ng &iacute;t nhất 30 ph&uacute;t mỗi ng&agrave;y), tr&aacute;nh stress v&agrave; kiểm tra sức khỏe định kỳ.</p>\r\n\r\n<p style=\"text-align:justify\"><strong>Lời Kết</strong></p>\r\n\r\n<p style=\"text-align:justify\">Đầu tư cho sức khỏe l&agrave; khoản đầu tư th&ocirc;ng minh v&agrave; bền vững nhất của mỗi người. H&atilde;y để HANA trở th&agrave;nh người bạn đồng h&agrave;nh tin cậy, bảo vệ bạn v&agrave; gia đ&igrave;nh trước những nguy cơ tai biến đột quỵ, tận hưởng một cuộc sống trọn vẹn: XANH &ndash; KHỎE &ndash; ĐẸP &ndash; AN TO&Agrave;N mỗi ng&agrave;y!</p>\r\n','BEM55IN7_Green2.jpg','',0,1250000,NULL,NULL,'2026-06-30','vn',1,1,'','','','',NULL,'',NULL,1,'','','','',NULL,NULL,'',NULL,'','','','',1),(107,48,'THỰC PHẨM BỔ SUNG NEST TUMERIC','thuc-pham-bo-sung-nest-tumeric','Trong cuộc sống hiện đại năng động, việc chăm sóc và bảo vệ sức khỏe hệ tiêu hóa trở thành mối quan tâm hàng đầu của nhiều gia đình. Thấu hiểu điều đó, Công ty Cổ phần Thương mại Xuất nhập khẩu Rono Nutrition - Chi nhánh Sài Gòn đã cho ra đời dòng sản phẩm cao cấp: Thực phẩm bổ sung Nest Tumeric (Sữa nghệ Nest Tumeric Nano Curcumin). Đây là sự kết hợp hoàn hảo giữa nguồn dinh dưỡng sữa tiên tiến và các tinh chất tự nhiên quý giá, mang lại giải pháp chăm sóc sức khỏe toàn diện và chủ động cho cả nhà.','<p><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sản phẩm sở hữu c&ocirc;ng thức cải tiến ưu việt với những &quot;th&agrave;nh phần v&agrave;ng&quot; được chứng minh l&acirc;m s&agrave;ng tốt cho cơ thể:</span></span></p>\r\n\r\n<ul>\r\n	<li><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong>Nano Curcumin cao cấp: </strong>Với k&iacute;ch thước si&ecirc;u nhỏ, Nano Curcumin dễ d&agrave;ng thẩm thấu nhanh v&agrave;o cơ thể, gi&uacute;p hỗ trợ l&agrave;m l&agrave;nh vết lo&eacute;t, bảo vệ ni&ecirc;m mạc dạ d&agrave;y v&agrave; t&aacute; tr&agrave;ng, giảm nhanh c&aacute;c triệu chứng đau r&aacute;t, đầy hơi v&agrave; kh&oacute; ti&ecirc;u.</span></span></li>\r\n	<li><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong>Sữa non Colostrum nhập khẩu từ Mỹ: </strong>Gi&agrave;u kh&aacute;ng thể IgG mang đến nguồn kh&aacute;ng thể tự nhi&ecirc;n dồi d&agrave;o, gi&uacute;p k&iacute;ch hoạt hệ thống miễn dịch, tăng cường sức đề kh&aacute;ng v&agrave; bảo vệ cơ thể trước c&aacute;c t&aacute;c nh&acirc;n g&acirc;y bệnh từ m&ocirc;i trường.</span></span></li>\r\n	<li><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong>Bột Tổ Yến &amp; Fucoidan: </strong>Sự kết hợp giữa thần dược bồi bổ tổ yến v&agrave; hoạt chất Fucoidan từ tảo biển gi&uacute;p th&uacute;c đẩy qu&aacute; tr&igrave;nh t&aacute;i tạo tế b&agrave;o, chống oxy h&oacute;a mạnh mẽ v&agrave; bổ sung nguồn năng lượng qu&yacute; gi&aacute; cho cơ thể phục hồi nhanh ch&oacute;ng.</span></span></li>\r\n	<li><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong>Hệ dưỡng chất to&agrave;n diện (DHA, Lysine, Taurine): </strong>Hỗ trợ ph&aacute;t triển tr&iacute; n&atilde;o, cải thiện thị lực v&agrave; k&iacute;ch th&iacute;ch vị gi&aacute;c gi&uacute;p ăn ngon miệng, tăng cường hấp thu dưỡng chất.</span></span></li>\r\n	<li><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong>Vị ngọt thanh từ đường Isomalt v&agrave; Cỏ ngọt Stevia: </strong>Sản phẩm kh&ocirc;ng sử dụng đường sinh năng lượng cao th&ocirc;ng thường m&agrave; thay bằng Isomalt v&agrave; cỏ ngọt tự nhi&ecirc;n, đảm bảo vị ngọt thơm ngon, dễ uống nhưng v&ocirc; c&ugrave;ng an to&agrave;n, ph&ugrave; hợp cho cả người ăn ki&ecirc;ng v&agrave; người gặp vấn đề về đường huyết.</span></span></li>\r\n</ul>\r\n\r\n<p><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#b45000\">- Đối tượng sử dụng đa dạng</span></span></strong></span></span></p>\r\n\r\n<p><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sữa nghệ Nest Tumeric được thiết kế tối ưu, ph&ugrave; hợp cho nhiều đối tượng kh&aacute;c nhau (trẻ em tr&ecirc;n 3 tuổi v&agrave; người lớn):</span></span></p>\r\n\r\n<ul>\r\n	<li><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Người gặp c&aacute;c vấn đề về dạ d&agrave;y, t&aacute; tr&agrave;ng, hệ ti&ecirc;u h&oacute;a k&eacute;m.</span></span></li>\r\n	<li><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Người cao tuổi cần bổ sung dinh dưỡng, phục hồi sức khỏe, tăng cường hệ miễn dịch.</span></span></li>\r\n	<li><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Phụ nữ mới sinh cần nhanh ch&oacute;ng l&agrave;nh vết thương, l&agrave;m đẹp da, chống l&atilde;o h&oacute;a v&agrave; lấy lại v&oacute;c d&aacute;ng.</span></span></li>\r\n	<li><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Người c&oacute; nhu cầu bổ sung vitamin, kho&aacute;ng chất v&agrave; bảo vệ sức khỏe chủ động h&agrave;ng ng&agrave;y.</span></span></li>\r\n</ul>\r\n\r\n<p><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#b45000\">- Hướng dẫn sử dụng v&agrave; bảo quản đ&uacute;ng c&aacute;ch</span></span></strong></span></span></p>\r\n\r\n<p><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Để đạt hiệu quả tốt nhất, người d&ugrave;ng n&ecirc;n tu&acirc;n thủ quy tr&igrave;nh pha sữa chuẩn:</span></span></p>\r\n\r\n<p><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong>&bull; C&aacute;ch pha: </strong>Pha 5 muỗng gạt ngang (khoảng 45g bột) với 180ml nước ấm (khoảng 40&deg;C - 50&deg;C) để được một ly sữa thơm ngon 200ml.<br />\r\n<strong>&bull; Liều lượng: </strong>Mỗi lần uống 1 ly, sử dụng từ 2 - 3 ly mỗi ng&agrave;y.<br />\r\n<strong>&bull; Lưu &yacute;: </strong>Uống ngay khi c&ograve;n ấm v&agrave; sử dụng trong v&ograve;ng 1 giờ sau khi pha. Đổ bỏ phần sữa uống dư.<br />\r\n<strong>&bull; Bảo quản: </strong>Nơi kh&ocirc; r&aacute;o, tho&aacute;ng m&aacute;t, tr&aacute;nh &aacute;nh nắng trực tiếp. Lon đ&atilde; mở nắp phải được đậy k&iacute;n v&agrave; sử dụng hết trong v&ograve;ng 4 tuần.</span></span></p>\r\n\r\n<p><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#b45000\">- Cam kết chất lượng v&agrave; nguồn gốc r&otilde; r&agrave;ng</span></span></strong></span></span></p>\r\n\r\n<p><span style=\"font-size:12pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sản phẩm được sản xuất tại nh&agrave; m&aacute;y hiện đại: <strong>Địa điểm kinh doanh - C&ocirc;ng ty Cổ phần Dinh dưỡng Hoa Kỳ HD - Ch&iacute; Linh</strong> tại Hải Dương, Việt Nam. Quy tr&igrave;nh sản xuất đạt đầy đủ c&aacute;c quy chuẩn kỹ thuật quốc gia về an to&agrave;n thực phẩm như QCVN 8-1:2011/BYT, QCVN 8-2:2011/BYT v&agrave; QCVN 8-3:2012/BYT. Kết quả kiểm nghiệm từ Trung t&acirc;m AVATEK khẳng định c&aacute;c chỉ ti&ecirc;u vi sinh vật, kim loại nặng v&agrave; độc tố vi nấm đều ho&agrave;n to&agrave;n đạt chuẩn an to&agrave;n, kh&ocirc;ng ph&aacute;t hiện tạp chất g&acirc;y hại.</span></span></p>\r\n','BEMBH5IC_z7996448155807_139aba3f6d26e59d7baa721671321f2d.jpg','',0,750000,NULL,NULL,'2026-06-01','vn',1,1,'','','Nest Tumeric - Món quà sức khỏe trọn vẹn cho cả gia đình!','',NULL,'',NULL,0,'','','','',NULL,NULL,'',NULL,'','','','',100),(92,48,'Sữa tắm on the Body','sua-tam-on-the-body','','','BCL5Q7H7_Suatambody.jpg','',0,250000,NULL,NULL,'2025-10-18','vn',1,1,'','','','',NULL,'',NULL,0,'','','','',NULL,NULL,'',NULL,'','','','',1),(100,48,'SRM Ý DĨ Ngừa Mụn','srm-y-di-ngua-mun','','','BCL5STT5_Nguamun.jpg','',0,100000,NULL,NULL,'2025-10-18','vn',1,1,'','','','',NULL,'',NULL,0,'','','','',NULL,NULL,'',NULL,'','','','',1),(101,48,'Sữa Tắm Ý DĨ','sua-tam-y-di','','','14ETCGKM_SuatamY.jpg','',0,180000,NULL,NULL,'2025-10-18','vn',1,1,'','','','',NULL,'',NULL,0,'','','','',NULL,NULL,'',NULL,'','','','',1),(106,48,'STRONG MEN PLUS','strong-men-plus','Strong Men Plus là dòng thực phẩm dinh dưỡng công thức đặc biệt được nghiên cứu và phát triển chuyên sâu dành riêng cho nam giới từ 18 tuổi trở lên. Sản phẩm sở hữu công thức tối ưu giúp bổ sung các dưỡng chất thiết yếu, không chỉ hỗ trợ tăng cường thể lực, nâng cao sức đề kháng mà còn đặc biệt chú trọng đến việc bảo vệ và nuôi dưỡng hệ xương khớp chắc khỏe dưới các tác động của quá trình vận động và lão hóa tự nhiên.','<p style=\"margin-left:9px; margin-right:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"color:#2b241f\">Strong Men Plus </span></strong><span dir=\"ltr\" lang=\"vi\" style=\"color:#2b241f\">l&agrave; d&ograve;ng thực phẩm dinh dưỡng c&ocirc;ng thức đặc biệt được nghi&ecirc;n cứu v&agrave; ph&aacute;t triển chuy&ecirc;n s&acirc;u d&agrave;nh ri&ecirc;ng cho nam giới từ 18 tuổi trở l&ecirc;n. Sản phẩm sở hữu c&ocirc;ng thức tối ưu gi&uacute;p bổ sung c&aacute;c dưỡng chất thiết yếu, kh&ocirc;ng chỉ hỗ trợ tăng cường thể lực, n&acirc;ng cao sức đề kh&aacute;ng m&agrave; c&ograve;n đặc biệt ch&uacute; trọng đến việc bảo vệ v&agrave; nu&ocirc;i dưỡng hệ xương khớp chắc khỏe dưới c&aacute;c t&aacute;c động của qu&aacute; tr&igrave;nh vận động v&agrave; l&atilde;o h&oacute;a tự nhi&ecirc;n.</span></span></span></p>\r\n\r\n<p style=\"margin-left:9px; margin-right:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"color:#2b241f\">Sản phẩm được sản xuất tr&ecirc;n d&acirc;y chuyền c&ocirc;ng nghệ hiện đại tại <strong>Nh&agrave; m&aacute;y Medical Milk &ndash; C&ocirc;ng ty Cổ phần Sữa Y tế </strong>(Địa chỉ: Số 10 Marina, Khu đ&ocirc; thị Ecopark, x&atilde; Phụng C&ocirc;ng, huyện Văn Giang, tỉnh Hưng Y&ecirc;n) v&agrave; chịu tr&aacute;ch nhiệm ph&acirc;n phối bởi <strong>C&ocirc;ng ty Cổ phần Dinh dưỡng Nutrilive</strong>. Sản phẩm đ&atilde; được Chi cục An to&agrave;n vệ sinh thực phẩm tỉnh Hưng Y&ecirc;n tiếp nhận bản c&ocirc;ng bố sản phẩm số <strong>45/2021/ĐKSP</strong>, đảm bảo c&aacute;c ti&ecirc;u chuẩn khắt khe nhất về an to&agrave;n thực phẩm theo quy định của Bộ Y tế.</span></span></span></p>\r\n\r\n<p style=\"margin-left:9px; margin-right:9px; text-align:justify\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:9px; margin-right:9px; text-align:justify\"><strong><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"color:#1a365d\">Đối Tượng Sử Dụng Mục Ti&ecirc;u</span></span></span></strong></p>\r\n\r\n<ul>\r\n	<li style=\"list-style-type:none\">\r\n	<ul>\r\n		<li><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"color:#2b241f\">Nam giới từ 18&nbsp;tuổi trở l&ecirc;n c&oacute; nhu cầu bổ sung dinh dưỡng hằng ng&agrave;y.</span></span></span></li>\r\n		<li><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"color:#2b241f\">Người thường xuy&ecirc;n vận động thể dục thể thao, l&agrave;m việc lao động nặng cần duy tr&igrave; năng lượng v&agrave; thể lực dẻo dai.</span></span></span></li>\r\n		<li><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"color:#2b241f\">Nam giới bước v&agrave;o độ tuổi trung ni&ecirc;n cần bảo vệ chức năng xương khớp, ph&ograve;ng ngừa lo&atilde;ng xương v&agrave; tho&aacute;i h&oacute;a.</span></span></span></li>\r\n		<li><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"color:#2b241f\">Người mới ốm dậy, cơ thể suy nhược cần nguồn dinh dưỡng dễ hấp thu để nhanh ch&oacute;ng phục hồi sức khỏe.</span></span></span></li>\r\n	</ul>\r\n	</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><a name=\"3._Lợi_Ích_Cốt_Lõi_Của_Strong_Men_Plus\"></a><strong><span dir=\"ltr\" lang=\"vi\" style=\"color:#1a365d\">Lợi &Iacute;ch Cốt L&otilde;i Của Strong Men Plus</span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:9px; margin-right:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"color:#2b241f\">Kh&aacute;c với c&aacute;c d&ograve;ng sữa th&ocirc;ng thường, Strong Men Plus mang lại t&aacute;c động k&eacute;p vượt trội gi&uacute;p ph&aacute;i mạnh duy tr&igrave; một cơ thể khỏe mạnh bền bỉ:</span></span></span></p>\r\n\r\n<p style=\"margin-left:39px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:12.0pt\"><span style=\"color:#1a365d\">Bảo Vệ Hệ Xương Khớp Chắc Khỏe</span></span></strong></span></span></p>\r\n\r\n<p style=\"margin-left:15px; margin-right:15px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"color:#2b241f\">Sản phẩm bổ sung h&agrave;m lượng Canxi, Vitamin D3 v&agrave; c&aacute;c kho&aacute;ng chất thiết yếu với tỉ lệ v&agrave;ng, gi&uacute;p tối ưu h&oacute;a qu&aacute; tr&igrave;nh t&aacute;i tạo m&ocirc; xương, tăng cường mật độ xương v&agrave; hỗ trợ b&ocirc;i trơn c&aacute;c khớp xương dẻo dai, giảm thiểu t&igrave;nh trạng đau nhức khi vận động.</span></span></span></p>\r\n\r\n<p style=\"margin-left:15px; margin-right:15px; text-align:justify\"><strong><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:12.0pt\"><span style=\"color:#1a365d\">Tăng Cường Sinh Lực &amp; Thể Trạng To&agrave;n Diện</span></span></span></span></strong></p>\r\n\r\n<p style=\"margin-left:15px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"color:#2b241f\">Cung cấp nguồn năng lượng sạch c&ugrave;ng hệ vi chất phong ph&uacute;, gi&uacute;p phục hồi cơ bắp nhanh ch&oacute;ng sau qu&aacute; tr&igrave;nh l&agrave;m việc hoặc tập luyện cường độ cao, khẳng định bản lĩnh v&agrave; phong độ bền bỉ của người đ&agrave;n &ocirc;ng.</span></span></span></p>\r\n\r\n<p style=\"margin-left:15px\">&nbsp;</p>\r\n\r\n<p style=\"margin-left:15px\"><strong><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><a name=\"4._Thông_Tin_Chi_Tiết_&amp;_Hướng_Dẫn_Sử_Dụn\"></a><span dir=\"ltr\" lang=\"vi\" style=\"color:#1a365d\">Th&ocirc;ng Tin Chi Tiết &amp; Hướng Dẫn Sử Dụng</span></span></span></strong></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<table cellspacing=\"0\" class=\"Table\" style=\"border-collapse:collapse; border:none; margin-left:10px\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"background-color:#ebf7ff; border-bottom:1px solid #cad4df; border-left:1px solid #cad4df; border-right:1px solid #cad4df; border-top:1px solid #cad4df; height:43px; vertical-align:top; width:204px\">\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#2a6baf\">T&ecirc;n sản phẩm</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"border-bottom:1px solid #cad4df; border-left:none; border-right:1px solid #cad4df; border-top:1px solid #cad4df; height:43px; vertical-align:top; width:476px\">\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#2b241f\">Thực phẩm d&agrave;nh cho chế độ ăn đặc biệt Strong Men Plus</span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#ebf7ff; border-bottom:1px solid #cad4df; border-left:1px solid #cad4df; border-right:1px solid #cad4df; border-top:none; height:65px; vertical-align:top; width:204px\">\r\n			<p>&nbsp;</p>\r\n\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#2a6baf\">Quy c&aacute;ch đ&oacute;ng g&oacute;i</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"border-bottom:1px solid #cad4df; border-left:none; border-right:1px solid #cad4df; border-top:none; height:65px; vertical-align:top; width:476px\">\r\n			<p style=\"margin-left:10px; margin-right:36px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#2b241f\">Lon/Hộp thiếc với c&aacute;c trọng lượng linh hoạt: 330g, 350g, 400g, 500g, 600g, 700g, 800g, 850g, 900g.</span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#ebf7ff; border-bottom:1px solid #cad4df; border-left:1px solid #cad4df; border-right:1px solid #cad4df; border-top:none; height:66px; vertical-align:top; width:204px\">\r\n			<p>&nbsp;</p>\r\n\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#2a6baf\">C&aacute;ch pha ti&ecirc;u chuẩn</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"border-bottom:1px solid #cad4df; border-left:none; border-right:1px solid #cad4df; border-top:none; height:66px; vertical-align:top; width:476px\">\r\n			<p style=\"margin-left:10px; margin-right:36px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#2b241f\">Pha 5 muỗng gạt ngang (tương đương 45g) với 180ml nước ấm (khoảng 40 - 50&deg;C) để được 1 ly sữa khoảng 200ml thơm ngon đầy đủ dinh dưỡng.</span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#ebf7ff; border-bottom:1px solid #cad4df; border-left:1px solid #cad4df; border-right:1px solid #cad4df; border-top:none; height:66px; vertical-align:top; width:204px\">\r\n			<p>&nbsp;</p>\r\n\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#2a6baf\">Liều lượng khuy&ecirc;n d&ugrave;ng</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"border-bottom:1px solid #cad4df; border-left:none; border-right:1px solid #cad4df; border-top:none; height:66px; vertical-align:top; width:476px\">\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#2b241f\">Uống ngay khi sữa c&ograve;n ấm. Sử dụng đều đặn từ 2 - 3 ly mỗi ng&agrave;y để đạt hiệu quả tối ưu nhất.</span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#ebf7ff; border-bottom:1px solid #cad4df; border-left:1px solid #cad4df; border-right:1px solid #cad4df; border-top:none; height:43px; vertical-align:top; width:204px\">\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#2a6baf\">Hạn sử dụng</span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"border-bottom:1px solid #cad4df; border-left:none; border-right:1px solid #cad4df; border-top:none; height:43px; vertical-align:top; width:476px\">\r\n			<p style=\"margin-left:10px\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.5pt\"><span style=\"color:#2b241f\">36 th&aacute;ng kể từ ng&agrave;y sản xuất (chi tiết in tr&ecirc;n vỏ hộp).</span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<h1 style=\"margin-left:42px\"><strong><span style=\"font-size:14pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><a name=\"5._Hướng_Dẫn_Bảo_Quản\"></a><span dir=\"ltr\" lang=\"vi\" style=\"color:#1a365d\">Hướng Dẫn Bảo Quản</span></span></span></strong></h1>\r\n\r\n<p style=\"margin-left:9px; margin-right:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span dir=\"ltr\" lang=\"vi\" style=\"color:#2b241f\">Để đảm bảo chất lượng sữa kh&ocirc;ng bị biến đổi, sản phẩm cần được bảo quản ở nơi kh&ocirc; r&aacute;o, tho&aacute;ng m&aacute;t, tr&aacute;nh &aacute;nh nắng mặt trời chiếu trực tiếp. Sau khi mở nắp hộp, lưu &yacute; đậy k&iacute;n v&agrave; kh&ocirc;ng bảo quản trong tủ lạnh; khuyến kh&iacute;ch sử dụng hết trong v&ograve;ng 3-4 tuần kể từ khi mở hộp. Đối với phần sữa đ&atilde; pha, n&ecirc;n uống ngay hoặc d&ugrave;ng hết trong v&ograve;ng 1 giờ, đổ bỏ phần sữa thừa nếu kh&ocirc;ng sử dụng hết.</span></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n','BEMBE2OL_strongmen.jpg','',0,560000,NULL,NULL,'2026-06-01','vn',1,1,'','','Giải Pháp Dinh Dưỡng Toàn Diện Nâng Tầm Phong Độ & Sức Khỏe Phái Mạnh','',NULL,'',NULL,0,'','','','',NULL,NULL,'',NULL,'','','','',1),(104,48,'Viên uống nội tiết 2XH Plus','vien-uong-noi-tiet-2xh-plus','2XH Plus không chỉ là một sản phẩm bổ sung thông thường mà là món quà kết tinh từ tinh hoa y học cổ truyền và công nghệ sản xuất hiện đại.','<p style=\"text-align:justify\"><img alt=\"\" style=\"height:!important;width:!important;\" src=\"/image/Noitiet1.jpg\" style=\"height:!important; width:!important\" /></p>\r\n\r\n<p style=\"text-align:justify\">Với chiết xuất 100% từ c&aacute;c dược liệu hữu cơ qu&yacute; hiếm, sản phẩm t&aacute;c động s&acirc;u v&agrave;o căn nguy&ecirc;n của sự thiếu hụt nội tiết, gi&uacute;p k&iacute;ch th&iacute;ch sản sinh hormone nữ một c&aacute;ch tự nhi&ecirc;n, an to&agrave;n v&agrave; bền vững m&agrave; kh&ocirc;ng g&acirc;y ra bất kỳ t&aacute;c dụng phụ n&agrave;o.</p>\r\n\r\n<p style=\"text-align:justify\">Tinh T&uacute;y Từ 8 Loại Dược Liệu Hữu Cơ 100%</p>\r\n\r\n<p style=\"text-align:justify\">Sự vượt trội của 2XH Plus nằm ở bảng th&agrave;nh phần v&agrave;ng với sự kết hợp ho&agrave;n hảo của c&aacute;c loại thảo dược thi&ecirc;n nhi&ecirc;n c&oacute; c&ocirc;ng năng bồi bổ cực kỳ mạnh mẽ:</p>\r\n\r\n<table cellspacing=\"0\" class=\"Table\" style=\"border-collapse:collapse; border:none; margin-left:25px\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"background-color:#f1f5f9; border-bottom:1px solid #e2e7f0; border-left:1px solid #e2e7f0; border-right:1px solid #e2e7f0; border-top:1px solid #e2e7f0; height:63px; vertical-align:top; width:156px\">\r\n			<p style=\"margin-left:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Microsoft Sans Serif&quot;,sans-serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">Th&agrave;nh Phần</span></span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f1f5f9; border-bottom:1px solid #e2e7f0; border-left:none; border-right:1px solid #e2e7f0; border-top:1px solid #e2e7f0; height:63px; vertical-align:top; width:468px\">\r\n			<p style=\"margin-left:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Microsoft Sans Serif&quot;,sans-serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">C&ocirc;ng Dụng Ch&iacute;nh Đối Với Sức Khỏe &amp; Sắc Đẹp V&ograve;ng Ngo&agrave;i</span></span></span></strong></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"border-bottom:1px solid #e2e7f0; border-left:1px solid #e2e7f0; border-right:1px solid #e2e7f0; border-top:none; height:77px; vertical-align:top; width:156px\">\r\n			<p style=\"margin-left:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Microsoft Sans Serif&quot;,sans-serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">S&acirc;m Tố Nữ</span></span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"border-bottom:1px solid #e2e7f0; border-left:none; border-right:1px solid #e2e7f0; border-top:none; height:77px; vertical-align:top; width:468px\">\r\n			<p style=\"margin-left:9px; margin-right:10px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Microsoft Sans Serif&quot;,sans-serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">Nguồn estrogen thực vật tự nhi&ecirc;n cực kỳ dồi d&agrave;o, gi&uacute;p c&acirc;n bằng nội tiết, cải thiện nhanh l&agrave;n da sạm n&aacute;m, tăng cường sinh l&yacute; nữ v&agrave; gi&uacute;p v&ograve;ng 1 săn chắc.</span></span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#f7fafb; border-bottom:1px solid #e2e7f0; border-left:1px solid #e2e7f0; border-right:1px solid #e2e7f0; border-top:none; height:61px; vertical-align:top; width:156px\">\r\n			<p style=\"margin-left:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Microsoft Sans Serif&quot;,sans-serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">Nh&acirc;n S&acirc;m</span></span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f7fafb; border-bottom:1px solid #e2e7f0; border-left:none; border-right:1px solid #e2e7f0; border-top:none; height:61px; vertical-align:top; width:468px\">\r\n			<p style=\"margin-left:9px; margin-right:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Microsoft Sans Serif&quot;,sans-serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">Đại bổ nguy&ecirc;n kh&iacute;, tăng cường sức đề kh&aacute;ng to&agrave;n diện, hỗ trợ chống oxy h&oacute;a mạnh mẽ v&agrave; cải thiện tr&iacute; nhớ.</span></span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"border-bottom:1px solid #e2e7f0; border-left:1px solid #e2e7f0; border-right:1px solid #e2e7f0; border-top:none; height:61px; vertical-align:top; width:156px\">\r\n			<p style=\"margin-left:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Microsoft Sans Serif&quot;,sans-serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">Đương Quy</span></span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"border-bottom:1px solid #e2e7f0; border-left:none; border-right:1px solid #e2e7f0; border-top:none; height:61px; vertical-align:top; width:468px\">\r\n			<p style=\"margin-left:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Microsoft Sans Serif&quot;,sans-serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">Bổ huyết, hoạt huyết, điều h&ograve;a chu kỳ kinh nguyệt, giảm hẳn c&aacute;c cơn đau bụng kinh v&agrave; hỗ trợ tối ưu cho sức khỏe sinh sản.</span></span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#f7fafb; border-bottom:1px solid #e2e7f0; border-left:1px solid #e2e7f0; border-right:1px solid #e2e7f0; border-top:none; height:47px; vertical-align:top; width:156px\">\r\n			<p style=\"margin-left:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Microsoft Sans Serif&quot;,sans-serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">Macca (Maca)</span></span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f7fafb; border-bottom:1px solid #e2e7f0; border-left:none; border-right:1px solid #e2e7f0; border-top:none; height:47px; vertical-align:top; width:468px\">\r\n			<p style=\"margin-left:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Microsoft Sans Serif&quot;,sans-serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">Gi&uacute;p cải thiện t&acirc;m trạng, n&acirc;ng cao sinh lực, điều h&ograve;a nội tiết v&agrave; bổ sung</span></span></span> <span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">năng lượng dồi d&agrave;o cho cơ thể.</span></span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p style=\"text-align:justify\">&nbsp;</p>\r\n\r\n<table cellspacing=\"0\" class=\"Table\" style=\"border-collapse:collapse; border:none; margin-left:25px\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"border-bottom:1px solid #e2e7f0; border-left:1px solid #e2e7f0; border-right:1px solid #e2e7f0; border-top:1px solid #e2e7f0; height:61px; vertical-align:top; width:156px\">\r\n			<p style=\"margin-left:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Microsoft Sans Serif&quot;,sans-serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">Củ Gai</span></span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"border-bottom:1px solid #e2e7f0; border-left:none; border-right:1px solid #e2e7f0; border-top:1px solid #e2e7f0; height:61px; vertical-align:top; width:468px\">\r\n			<p style=\"margin-left:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Microsoft Sans Serif&quot;,sans-serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">Thanh nhiệt giải độc, bảo vệ tử cung, giảm thiểu nguy cơ vi&ecirc;m nhiễm phụ khoa v&agrave; hỗ trợ hệ ti&ecirc;u h&oacute;a.</span></span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#f7fafb; border-bottom:1px solid #e2e7f0; border-left:1px solid #e2e7f0; border-right:1px solid #e2e7f0; border-top:none; height:63px; vertical-align:top; width:156px\">\r\n			<p style=\"margin-left:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Microsoft Sans Serif&quot;,sans-serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">Đan S&acirc;m</span></span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f7fafb; border-bottom:1px solid #e2e7f0; border-left:none; border-right:1px solid #e2e7f0; border-top:none; height:63px; vertical-align:top; width:468px\">\r\n			<p style=\"margin-left:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Microsoft Sans Serif&quot;,sans-serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">Gi&uacute;p th&ocirc;ng kinh mạch, lưu th&ocirc;ng kh&iacute; huyết tối ưu, bảo vệ hệ tim mạch vững chắc v&agrave; kh&aacute;ng vi&ecirc;m hiệu quả.</span></span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"border-bottom:1px solid #e2e7f0; border-left:1px solid #e2e7f0; border-right:1px solid #e2e7f0; border-top:none; height:61px; vertical-align:top; width:156px\">\r\n			<p style=\"margin-left:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Microsoft Sans Serif&quot;,sans-serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">Ph&aacute; Cố Chỉ</span></span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"border-bottom:1px solid #e2e7f0; border-left:none; border-right:1px solid #e2e7f0; border-top:none; height:61px; vertical-align:top; width:468px\">\r\n			<p style=\"margin-left:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Microsoft Sans Serif&quot;,sans-serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">Hỗ trợ k&iacute;ch th&iacute;ch tăng sinh collagen tự nhi&ecirc;n, phục hồi v&agrave; t&aacute;i tạo l&agrave;n da, cải thiện chức năng của hệ cơ xương khớp.</span></span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#f7fafb; border-bottom:1px solid #e2e7f0; border-left:1px solid #e2e7f0; border-right:1px solid #e2e7f0; border-top:none; height:61px; vertical-align:top; width:156px\">\r\n			<p style=\"margin-left:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Microsoft Sans Serif&quot;,sans-serif\"><strong><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">Mộc Th&ocirc;ng</span></span></span></strong></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#f7fafb; border-bottom:1px solid #e2e7f0; border-left:none; border-right:1px solid #e2e7f0; border-top:none; height:61px; vertical-align:top; width:468px\">\r\n			<p style=\"margin-left:9px; text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:&quot;Microsoft Sans Serif&quot;,sans-serif\"><span dir=\"ltr\" lang=\"vi\" style=\"font-size:10.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"><span style=\"color:black\">Lợi niệu, th&ocirc;ng mạch, giảm t&igrave;nh trạng tiểu buốt, tiểu rắt v&agrave; hỗ trợ l&agrave;m giảm sưng vi&ecirc;m.</span></span></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p style=\"text-align:justify\">Lộ Tr&igrave;nh Cải Thiện Nội Tiết R&otilde; Rệt</p>\r\n\r\n<p style=\"text-align:justify\">Sử dụng đều đặn vi&ecirc;n uống nội tiết 2XH Plus mang lại những thay đổi t&iacute;ch cực r&otilde; rệt theo từng giai đoạn của liệu tr&igrave;nh:</p>\r\n\r\n<p style=\"text-align:justify\">●&nbsp;&nbsp; &nbsp;Sau 6 tuần - Giai đoạn Khởi động: L&agrave;m giảm nhanh c&aacute;c cơn bốc hỏa, hạn chế đổ mồ h&ocirc;i đ&ecirc;m v&agrave; cải thiện giấc ngủ. Đồng thời, khắc phục t&igrave;nh trạng kh&ocirc; hạn v&ugrave;ng k&iacute;n, tăng ham muốn v&agrave; hỗ trợ lấy lại chu kỳ kinh nguyệt NHIỀU - ĐỀU - ĐẸP.</p>\r\n\r\n<p style=\"text-align:justify\">●&nbsp;&nbsp; &nbsp;Sau 9 tuần - Giai đoạn T&aacute;i tạo: Nu&ocirc;i dưỡng v&agrave; t&aacute;i tạo l&agrave;n da mịn m&agrave;ng, l&agrave;m giảm t&igrave;nh trạng rụng t&oacute;c một c&aacute;ch r&otilde; rệt. Gi&uacute;p ổn định kinh nguyệt, c&acirc;n bằng s&acirc;u hệ nội tiết v&agrave; hỗ trợ đ&agrave;o thải, giảm mỡ bụng hiệu quả.</p>\r\n\r\n<p style=\"text-align:justify\">●&nbsp;&nbsp; &nbsp;Sau 12 tuần - Giai đoạn Duy tr&igrave; &amp; Vững chắc: Định h&igrave;nh ổn định nội tiết nữ l&acirc;u d&agrave;i. Mang lại giấc ngủ s&acirc;u, đủ giấc, tăng cường tr&iacute; nhớ, n&acirc;ng đỡ v&agrave; l&agrave;m săn chắc v&ograve;ng 1. Đồng thời tăng chức năng xương khớp, n&acirc;ng cao hệ miễn dịch v&agrave; chủ động ph&ograve;ng ngừa c&aacute;c bệnh tim mạch.</p>\r\n\r\n<p style=\"text-align:justify\">Giải Ph&aacute;p V&agrave;ng X&oacute;a Bỏ Nỗi Lo Cho Phụ Nữ Sau Sinh</p>\r\n\r\n<p style=\"text-align:justify\">Giai đoạn sau sinh l&agrave; thời điểm nồng độ nội tiết tố của phụ nữ suy giảm trầm trọng, dẫn đến h&agrave;ng loạt hệ lụy về t&acirc;m sinh l&yacute;. 2XH Plus ch&iacute;nh l&agrave; &quot;cứu c&aacute;nh&quot; l&yacute; tưởng gi&uacute;p giải quyết triệt để 3 nh&oacute;m vấn đề cốt l&otilde;i:</p>\r\n\r\n<p style=\"text-align:justify\">Kh&ocirc; hạn, rối loạn kinh nguyệt: Tăng cường b&ocirc;i trơn &acirc;m đạo, giảm đau r&aacute;t khi quan hệ, lấy lại sự thăng hoa trong đời sống vợ chồng.<br />\r\n●&nbsp;&nbsp; &nbsp;Vi&ecirc;m nhiễm, nấm ngứa, m&ugrave;i h&ocirc;i: C&aacute;c dược liệu kh&aacute;ng vi&ecirc;m gi&uacute;p se kh&iacute;t v&ugrave;ng k&iacute;n, đ&agrave;o thải kh&iacute; hư v&agrave; giữ cho v&ugrave;ng nhạy cảm lu&ocirc;n sạch sẽ, thơm tho.</p>\r\n\r\n<p style=\"text-align:justify\">●&nbsp;&nbsp; &nbsp;C&aacute;u gắt, kh&oacute; ngủ, bốc hỏa: L&agrave;m dịu hệ thần kinh, điều h&ograve;a t&acirc;m trạng, xua tan căng thẳng v&agrave; mệt mỏi k&eacute;o d&agrave;i.<br />\r\nHướng Dẫn Sử Dụng&nbsp;<br />\r\nĐể sản phẩm ph&aacute;t huy tối đa c&ocirc;ng dụng, người d&ugrave;ng cần tu&acirc;n thủ đ&uacute;ng liều lượng v&agrave; lộ tr&igrave;nh khuyến c&aacute;o từ chuy&ecirc;n gia:</p>\r\n\r\n<p style=\"text-align:justify\">●&nbsp;&nbsp; &nbsp;Liều d&ugrave;ng chuẩn: Uống 4 vi&ecirc;n/ng&agrave;y, chia l&agrave;m 2 lần sử dụng.</p>\r\n\r\n<p style=\"text-align:justify\">●&nbsp;&nbsp; &nbsp;Thời điểm d&ugrave;ng: Uống sau c&aacute;c bữa ăn ch&iacute;nh trong ng&agrave;y để hấp thu dưỡng chất tốt nhất.</p>\r\n\r\n<p style=\"text-align:justify\">●&nbsp;&nbsp; &nbsp;Liệu tr&igrave;nh khuyến nghị: N&ecirc;n sử dụng li&ecirc;n tục v&agrave; đều đặn từ 2 &ndash; 3 th&aacute;ng để cảm nhận sự thay đổi to&agrave;n diện v&agrave; duy tr&igrave; kết quả bền vững.</p>\r\n\r\n<p style=\"text-align:justify\">Cam Kết Chất Lượng</p>\r\n\r\n<p style=\"text-align:justify\">T-LAB lu&ocirc;n đặt sức khỏe v&agrave; sự an to&agrave;n của người ti&ecirc;u d&ugrave;ng l&ecirc;n h&agrave;ng đầu với những cam kết nghi&ecirc;m ngặt:</p>\r\n\r\n<p style=\"text-align:justify\">1.&nbsp;&nbsp; &nbsp;Sản phẩm được sản xuất tại hệ thống nh&agrave; m&aacute;y hiện đại đạt chuẩn GMP, được kiểm định khắt khe trước khi ra thị trường.</p>\r\n\r\n<p style=\"text-align:justify\">2.&nbsp;&nbsp; &nbsp;N&oacute;i kh&ocirc;ng với c&aacute;c th&agrave;nh phần hormone tổng hợp, kh&ocirc;ng g&acirc;y ảnh hưởng ti&ecirc;u cực đến chức năng sinh sản tự nhi&ecirc;n.</p>\r\n\r\n<p style=\"text-align:justify\">3.&nbsp;&nbsp; &nbsp;Hiệu quả r&otilde; rệt, cải thiện r&otilde; r&agrave;ng c&aacute;c t&igrave;nh trạng bốc hỏa, kh&ocirc; hạn ngay sau 4 &ndash; 6 tuần đầu sử dụng.</p>\r\n','BEM5C85I_Noitiet2.jpg','',0,850000,NULL,NULL,'2026-06-30','vn',1,1,'','','','',NULL,'',NULL,1,'','','','',NULL,NULL,'',NULL,'','','','',1),(105,48,'NHẤT XUÂN GLUTATHION','nhat-xuan-glutathion','Thời gian và áp lực cuộc sống chính là \"kẻ thù\" thầm lặng tàn phá nhan sắc và sức khỏe của người phụ nữ.','<p style=\"text-align:justify\"><img alt=\"\" style=\"height:!important;width:!important;\" src=\"/image/Nhatxuan2.jpg\" style=\"height:!important; width:!important\" /></p>\r\n\r\n<p style=\"text-align:justify\">Bước qua tuổi thanh xu&acirc;n, h&agrave;ng loạt dấu hiệu suy giảm nội tiết tố g&otilde; cửa: l&agrave;n da xuất hiện n&aacute;m sạm, t&agrave;n nhang, những vết nhăn nơi kh&oacute;e mắt, đi k&egrave;m với đ&oacute; l&agrave; t&igrave;nh trạng bốc hỏa, mất ngủ, kh&ocirc; hạn v&agrave; mệt mỏi k&eacute;o d&agrave;i. Đ&oacute; l&agrave; l&uacute;c cơ thể l&ecirc;n tiếng cần được chăm s&oacute;c s&acirc;u từ b&ecirc;n trong.</p>\r\n\r\n<p style=\"text-align:justify\">Thấu hiểu s&acirc;u sắc h&agrave;nh tr&igrave;nh g&igrave;n giữ thanh xu&acirc;n của ph&aacute;i đẹp, vi&ecirc;n uống Nhất Xu&acirc;n Glutathion ra đời như một giải ph&aacute;p cứu c&aacute;nh to&agrave;n diện, kết hợp đột ph&aacute; giữa tinh hoa y học cổ truyền v&agrave; hoạt chất thế hệ mới gi&uacute;p hồi sinh l&agrave;n da v&agrave; c&acirc;n bằng nội tiết tố một c&aacute;ch tự nhi&ecirc;n nhất.</p>\r\n\r\n<p style=\"text-align:justify\">C&ocirc;ng thức đột ph&aacute; từ 9 loại thảo dược v&agrave; dưỡng chất qu&yacute;.</p>\r\n\r\n<p style=\"text-align:justify\">Nhất Xu&acirc;n Glutathion tự h&agrave;o sở hữu bảng th&agrave;nh phần v&agrave;ng, được chọn lọc khắt khe để mang lại hiệu quả vượt trội:</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Tăng cường lưu th&ocirc;ng m&aacute;u &amp; Hoạt huyết</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;&Iacute;ch Mẫu: Chứa Vitamin A v&agrave; hoạt chất Leonurin gi&uacute;p tăng cường lưu th&ocirc;ng tuần ho&agrave;n m&aacute;u, hỗ trợ l&agrave;m tan cục m&aacute;u đ&ocirc;ng, điều h&ograve;a kinh nguyệt v&agrave; bổ huyết, mang lại thần sắc tươi tắn.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Đương Quy: Nguồn vitamin E, B1, B2 phong ph&uacute; gi&uacute;p sản sinh hồng cầu, đưa m&aacute;u nu&ocirc;i dưỡng tế b&agrave;o da, x&oacute;a mờ vết th&acirc;m n&aacute;m, nu&ocirc;i da mềm mại hồng h&agrave;o.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Hồng Hoa &amp; Xuy&ecirc;n Khung: Bộ đ&ocirc;i hoạt huyết mạnh mẽ gi&uacute;p loại bỏ m&aacute;u ứ, cải thiện vi tuần ho&agrave;n, ngăn ngừa thiếu m&aacute;u v&agrave; điều h&ograve;a kinh nguyệt ổn định.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Trẻ h&oacute;a tế b&agrave;o &amp; C&acirc;n bằng nội tiết.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;S&acirc;m Tố Nữ: Chứa hoạt chất Deoxymiroestrogen &ndash; loại estrogen thực vật cực mạnh gi&uacute;p đẩy l&ugrave;i sạm n&aacute;m, tăng sản sinh Collagen tự nhi&ecirc;n, gi&uacute;p da săn chắc v&agrave; tăng cường chức năng sinh l&yacute; nữ.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Hồng S&acirc;m: Hoạt chất Gisenosid v&agrave; Adaptogenic gi&uacute;p an thần, tỉnh t&aacute;o, giảm căng thẳng stress v&agrave; trẻ h&oacute;a từ s&acirc;u trong tế b&agrave;o.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Hạt Mắc Ca: Gi&agrave;u Omega, protein v&agrave; kho&aacute;ng chất bảo vệ tim mạch, nu&ocirc;i dưỡng m&oacute;ng, t&oacute;c v&agrave; chống l&atilde;o h&oacute;a to&agrave;n diện.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Glutathione &amp; Collagen Peptide: Bộ đ&ocirc;i kinh điển gi&uacute;p bật t&ocirc;ng trắng da, ngăn chặn hắc sắc tố melanin v&agrave; lấp đầy c&aacute;c nếp nhăn.</p>\r\n\r\n<p style=\"text-align:justify\">C&ocirc;ng dụng ưu việt của Nhất Xu&acirc;n Glutathion</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Nu&ocirc;i dưỡng l&agrave;n da: Mờ n&aacute;m sạm da, giảm mụn nội tiết, l&agrave;m mờ nếp nhăn, gi&uacute;p da trắng hồng, căng mịn.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;C&acirc;n bằng nội tiết tố: Giảm nhanh c&aacute;c triệu chứng kh&oacute; chịu của giai đoạn tiền m&atilde;n kinh v&agrave; m&atilde;n kinh như bốc hỏa, đổ mồ h&ocirc;i, rối loạn kinh nguyệt.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Cải thiện sức khỏe thể chất: Hỗ trợ điều trị mất ngủ, gi&uacute;p ngủ ngon v&agrave; s&acirc;u giấc; tăng cường thể lực v&agrave; tuần ho&agrave;n m&aacute;u n&atilde;o.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Chăm s&oacute;c thầm k&iacute;n: Giảm kh&ocirc; hạn, đ&agrave;o thải vi&ecirc;m nhiễm phụ khoa, hỗ trợ l&agrave;m tan cục m&aacute;u đ&ocirc;ng hiệu quả.</p>\r\n\r\n<p style=\"text-align:justify\">Hướng dẫn sử dụng&nbsp;</p>\r\n\r\n<p style=\"text-align:justify\">Sản phẩm được đ&oacute;ng g&oacute;i tiện lợi: Hộp 60 vi&ecirc;n (hoặc quy c&aacute;ch lọ 30 vi&ecirc;n tiện dụng đi k&egrave;m trong hộp lớn).</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Sản phẩm l&agrave; thực phẩm bảo vệ sức khỏe, kh&ocirc;ng phải l&agrave; thuốc v&agrave; kh&ocirc;ng c&oacute; chức năng thay thế thuốc chữa bệnh.</p>\r\n\r\n<p style=\"text-align:justify\">&bull;&nbsp;&nbsp; &nbsp;Hiệu quả ph&aacute;t huy tốt nhất khi sử dụng đủ liệu tr&igrave;nh theo khuyến c&aacute;o v&agrave; t&ugrave;y thuộc v&agrave;o sự hấp thu của từng cơ địa.</p>\r\n','BEM5EEGV_Nhatxuan1.jpg','',0,850000,NULL,NULL,'2026-06-30','vn',1,1,'','','','',NULL,'',NULL,0,'','','','',NULL,NULL,'',NULL,'','','','',1),(108,48,'THỰC PHẨM BỔ SUNG UTRA NUTRI L68 (Hộp 20 gói)','thuc-pham-bo-sung-utra-nutri-l68-hop-20-goi','Trong cuộc sống hiện đại năng động, xu hướng tìm kiếm một giải pháp dinh dưỡng vừa nhanh chóng, tiện lợi, lại vừa đảm bảo sức khỏe toàn diện đang trở thành ưu tiên hàng đầu. Hiểu được nhu cầu bức thiết đó, Công ty Cổ phần Thương mại Xuất nhập khẩu RONO Nutrition cùng các chuyên gia hàng đầu đã nghiên cứu và cho ra mắt sản phẩm UTRA NUTRI L68. Đây không chỉ đơn thuần là một sản phẩm ngũ cốc thông thường, mà là một sản phẩm dinh dưỡng chuyên biệt, tích hợp sức mạnh đột phá của khoa học thực phẩm thế hệ mới.','<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong><span style=\"font-size:13.0pt\"><span style=\"color:#004b49\">HỆ TH&Agrave;NH PHẦN V&Agrave;NG V&Agrave; C&Ocirc;NG DỤNG ĐỘT PH&Aacute; CHI TIẾT</span></span></strong></span></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong><span style=\"color:#bf4f00\">1. Tinh bột kh&aacute;ng thế hệ mới (Từ bột chuối xanh)</span></strong></span></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">L&agrave; nguồn thức ăn thượng hạng nu&ocirc;i dưỡng hệ vi sinh vật c&oacute; lợi trong đường ruột. Tinh bột kh&aacute;ng đi qua dạ d&agrave;y v&agrave; ruột non m&agrave; kh&ocirc;ng bị ti&ecirc;u h&oacute;a, xuống thẳng đại tr&agrave;ng, tạo ra c&aacute;c axit b&eacute;o chuỗi ngắn gi&uacute;p l&agrave;m sạch hệ thống đường ruột, hỗ trợ cải thiện hiệu quả c&aacute;c vấn đề về ti&ecirc;u h&oacute;a như t&aacute;o b&oacute;n, ti&ecirc;u chảy, tr&agrave;o ngược dạ d&agrave;y, đồng thời gi&uacute;p ổn định đường huyết v&agrave; hỗ trợ chức năng chuyển h&oacute;a tự nhi&ecirc;n của cơ thể.</span></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong><span style=\"color:#bf4f00\">2. Sự kết hợp của c&aacute;c Si&ecirc;u Dược Liệu Qu&yacute; Hiếm</span></strong></span></span></span></p>\r\n\r\n<ul>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong>Đ&ocirc;ng tr&ugrave;ng hạ thảo (2000 mcg/100g): </strong>Tăng cường thể chất, giảm mệt mỏi, n&acirc;ng cao hệ miễn dịch, chống l&atilde;o h&oacute;a mạnh mẽ v&agrave; bảo vệ to&agrave;n diện chức năng gan, thận, tim mạch.</span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong>Fucoidan (900 mcg/100g): </strong>Chiết xuất tảo n&acirc;u qu&yacute; gi&aacute;, c&oacute; t&aacute;c dụng chống oxy h&oacute;a mạnh, hỗ trợ tăng cường tế b&agrave;o miễn dịch tự nhi&ecirc;n v&agrave; hỗ trợ đắc lực trong qu&aacute; tr&igrave;nh ph&ograve;ng ngừa, điều trị ung thư.</span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong>Nano Curcumin: </strong>Với k&iacute;ch thước si&ecirc;u ph&acirc;n tử gi&uacute;p hấp thu tối đa, hỗ trợ l&agrave;m l&agrave;nh nhanh c&aacute;c vết lo&eacute;t, giảm đau dạ d&agrave;y v&agrave; giảm tiết axit dịch vị hiệu quả.</span></span></span></li>\r\n</ul>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong><span style=\"color:#bf4f00\">3. Phức hợp 10 loại hạt dinh dưỡng cao cấp</span></strong></span></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">Bao gồm: Hạnh nh&acirc;n, Hạt &oacute;c ch&oacute;, Yến mạch, Hạt điều, Hạt chia, Hạt sen, Gạo lứt, M&egrave; đen, &Yacute; dĩ, Sachi. Sự kết hợp n&agrave;y mang lại nguồn vitamin, kho&aacute;ng chất phong ph&uacute; c&ugrave;ng lượng chất xơ dồi d&agrave;o, chất b&eacute;o kh&ocirc;ng b&atilde;o h&ograve;a tốt cho tim mạch v&agrave; n&atilde;o bộ, đồng thời đem lại hương vị thơm ngon, b&ugrave;i ngậy tự nhi&ecirc;n dễ uống.</span></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong><span style=\"color:#bf4f00\">4. Đường Isomalt v&agrave; Muối Hồng tự nhi&ecirc;n</span></strong></span></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">Sản phẩm sử dụng đường Isomalt c&oacute; chỉ số đường huyết cực thấp, kết hợp c&ugrave;ng Muối Hồng gi&uacute;p bổ sung c&aacute;c kho&aacute;ng chất vi lượng tự nhi&ecirc;n, ngăn ngừa mất nước, ổn định huyết &aacute;p, cực kỳ an to&agrave;n v&agrave; ph&ugrave; hợp cho người ăn ki&ecirc;ng, ăn chay, người mắc bệnh tiểu đường.</span></span></span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#004b49\">ĐỐI TƯỢNG SỬ DỤNG L&Yacute; TƯỞNG</span></span></strong></span></span></span></p>\r\n\r\n<ul>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">Trẻ em từ 6 tuổi trở l&ecirc;n v&agrave; người lớn cần bổ sung dinh dưỡng.</span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">Người bị rối loạn chuyển h&oacute;a, người thừa c&acirc;n, b&eacute;o ph&igrave; hoặc người gầy kh&oacute; hấp thụ.</span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">Người gặp c&aacute;c vấn đề về đường ti&ecirc;u h&oacute;a như t&aacute;o b&oacute;n m&atilde;n t&iacute;nh, ti&ecirc;u chảy, tr&agrave;o ngược dạ d&agrave;y, vi&ecirc;m đại tr&agrave;ng.</span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">Người mắc bệnh l&yacute; tiểu đường, tiền tiểu đường, người cao tuổi c&oacute; nguy cơ tim mạch, huyết &aacute;p.</span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">Người theo đuổi chế độ ăn ki&ecirc;ng l&agrave;nh mạnh, ăn chay hoặc người bận rộn cần một bữa ăn phụ đầy đủ chất.</span></span></span></li>\r\n</ul>\r\n\r\n<p style=\"margin-left:24px\">&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#004b49\">TH&Ocirc;NG TIN DINH DƯỠNG C&Ocirc;NG BỐ (TRONG 100G)</span></span></strong></span></span></span></p>\r\n\r\n<table cellspacing=\"0\" class=\"MsoTableLightShadingAccent1\" style=\"border-collapse:collapse; border:none\">\r\n	<tbody>\r\n		<tr>\r\n			<td style=\"background-color:#004b49; border-bottom:1px solid #4f81bd; border-left:none; border-right:none; border-top:1px solid #4f81bd; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong><span style=\"color:white\">Th&agrave;nh phần dinh dưỡng</span></strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#004b49; border-bottom:1px solid #4f81bd; border-left:none; border-right:none; border-top:1px solid #4f81bd; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong><span style=\"color:white\">Đơn vị t&iacute;nh</span></strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#004b49; border-bottom:1px solid #4f81bd; border-left:none; border-right:none; border-top:1px solid #4f81bd; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong><span style=\"color:white\">Gi&aacute; trị c&ocirc;ng bố</span></strong></span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#d3dfee; border-bottom:none; border-left:none; border-right:none; border-top:none; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong>Năng lượng</strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#d3dfee; border-bottom:none; border-left:none; border-right:none; border-top:none; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">kcal</span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#d3dfee; border-bottom:none; border-left:none; border-right:none; border-top:none; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">350.8</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"border-bottom:none; border-left:none; border-right:none; border-top:none; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong>Chất đạm</strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"border-bottom:none; border-left:none; border-right:none; border-top:none; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">g</span></span></span></p>\r\n			</td>\r\n			<td style=\"border-bottom:none; border-left:none; border-right:none; border-top:none; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">4.66</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#d3dfee; border-bottom:none; border-left:none; border-right:none; border-top:none; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong>Chất b&eacute;o</strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#d3dfee; border-bottom:none; border-left:none; border-right:none; border-top:none; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">g</span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#d3dfee; border-bottom:none; border-left:none; border-right:none; border-top:none; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">8.33</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"border-bottom:none; border-left:none; border-right:none; border-top:none; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong>Carbohydrat (Kh&ocirc;ng gồm xơ)</strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"border-bottom:none; border-left:none; border-right:none; border-top:none; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">g</span></span></span></p>\r\n			</td>\r\n			<td style=\"border-bottom:none; border-left:none; border-right:none; border-top:none; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">64.3</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"background-color:#d3dfee; border-bottom:none; border-left:none; border-right:none; border-top:none; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong>Natri</strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#d3dfee; border-bottom:none; border-left:none; border-right:none; border-top:none; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">mg</span></span></span></p>\r\n			</td>\r\n			<td style=\"background-color:#d3dfee; border-bottom:none; border-left:none; border-right:none; border-top:none; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">176</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td style=\"border-bottom:1px solid #4f81bd; border-left:none; border-right:none; border-top:none; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong>Đường tổng số</strong></span></span></span></p>\r\n			</td>\r\n			<td style=\"border-bottom:1px solid #4f81bd; border-left:none; border-right:none; border-top:none; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">g</span></span></span></p>\r\n			</td>\r\n			<td style=\"border-bottom:1px solid #4f81bd; border-left:none; border-right:none; border-top:none; vertical-align:top; width:208px\">\r\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">11.6</span></span></span></p>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<p><br />\r\n&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#004b49\">HƯỚNG DẪN SỬ DỤNG V&Agrave; BẢO QUẢN Đ&Uacute;NG C&Aacute;CH</span></span></strong></span></span></span></p>\r\n\r\n<ol>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">Bước 1: Rửa sạch tay v&agrave; đảm bảo c&aacute;c vật dụng pha chế ho&agrave;n to&agrave;n sạch sẽ.</span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">Bước 2: Cho khoảng 180ml nước n&oacute;ng v&agrave;o ly/cốc.</span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">Bước 3: Cho 1 g&oacute;i bột UTRA NUTRI L68 (25g) v&agrave;o cốc, khuấy đều cho tan ho&agrave;n to&agrave;n v&agrave; thưởng thức. C&oacute; thể th&ecirc;m đ&aacute; nếu muốn uống lạnh hoặc d&ugrave;ng b&igrave;nh lắc (shaker) để tăng độ mịn.</span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">Liều lượng khuyến nghị: Sử dụng từ 2 đến 3 ly mỗi ng&agrave;y để cung cấp dinh dưỡng, đ&agrave;o thải độc tố v&agrave; hỗ trợ hệ ti&ecirc;u h&oacute;a tốt nhất.</span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">Bảo quản: Đậy k&iacute;n nắp sau mỗi lần sử dụng. Bảo quản nơi kh&ocirc; r&aacute;o, tho&aacute;ng m&aacute;t, tr&aacute;nh &aacute;nh nắng mặt trực tiếp từ mặt trời.</span></span></span></li>\r\n</ol>\r\n\r\n<p style=\"margin-left:24px\">&nbsp;</p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\"><strong><span style=\"font-size:14.0pt\"><span style=\"color:#004b49\">CAM KẾT CHẤT LƯỢNG V&Agrave; UY T&Iacute;N THƯƠNG HIỆU</span></span></strong></span></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Arial,sans-serif\"><span style=\"color:#333333\">Sản phẩm UTRA NUTRI L68 được sản xuất tại nh&agrave; m&aacute;y đạt ti&ecirc;u chuẩn quốc tế nghi&ecirc;m ngặt của C&ocirc;ng ty Cổ phần Dinh dưỡng Hoa Kỳ HD &ndash; Ch&iacute; Linh (Hải Dương). Sản phẩm c&oacute; đầy đủ Hồ sơ Tự c&ocirc;ng bố số 12/Rono Nutrition/2025 v&agrave; đ&atilde; trải qua c&aacute;c đợt kiểm nghiệm khắt khe về vi sinh, kim loại nặng, độc tố vi nấm tại Trung t&acirc;m Kiểm nghiệm AVATEK đạt chuẩn ISO/IEC 17025:2017, đảm bảo an to&agrave;n tuyệt đối cho người ti&ecirc;u d&ugrave;ng. Tr&ecirc;n bao b&igrave; sản phẩm vinh hạnh sở hữu c&aacute;c chứng nhận uy t&iacute;n h&agrave;ng đầu như FDA (Cục quản l&yacute; Thực phẩm v&agrave; Dược phẩm Hoa Kỳ) v&agrave; chuẩn thực h&agrave;nh sản xuất tốt GMP.</span></span></span></p>\r\n','BEMBJ9SO_z7996448142306_860b95279af27566672386e467487033.jpg','',0,1200000,NULL,NULL,'2026-06-01','vn',1,1,'','','UTRA NUTRI L68 – CHĂM SÓC TỪ TÂM, NÂNG TẦM CUỘC SỐNG!','',NULL,'',NULL,0,'','','','',NULL,NULL,'',NULL,'','','','',1),(109,48,'Nước Giặt Xả Cao Cấp Booster 2in1','nuoc-giat-xa-cao-cap-booster-2in1','Nước giặt xả 2 trong 1 Booster – Gia tăng sức mạnh giặt tẩy, mang lại giải pháp chăm sóc gia đình toàn diện và tiết kiệm nhất.','<p><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#003399\">1. C&ocirc;ng nghệ đột ph&aacute; từ Hệ 6 Enzyme tự nhi&ecirc;n (Enzyme Power)</span></span></span></strong></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Điểm tạo n&ecirc;n sự kh&aacute;c biệt vượt trội của nước giặt xả Booster ch&iacute;nh l&agrave; c&ocirc;ng thức t&iacute;ch hợp từ 6 loại enzyme tự nhi&ecirc;n thế hệ mới, gi&uacute;p ph&acirc;n hủy v&agrave; đ&aacute;nh bật mọi vết bẩn cứng đầu m&agrave; kh&ocirc;ng cần v&ograve; mạnh:</span></span></span></span></p>\r\n\r\n<ul>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Proteaza: Chuy&ecirc;n xử l&yacute; v&agrave; ph&acirc;n hủy c&aacute;c vết bẩn dạng protein (như vết m&aacute;u, mồ h&ocirc;i, sữa, thức ăn).</span></span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Lipaza: Đ&aacute;nh tan c&aacute;c vết bẩn cứng đầu dạng dầu mỡ, dầu ăn, b&atilde; nhờn b&aacute;m tr&ecirc;n cổ &aacute;o.</span></span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Amylaza: Tẩy sạch hiệu quả c&aacute;c vết bẩn từ tinh bột, tương ớt, nước sốt.</span></span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Xenlulaza: Thấm s&acirc;u l&agrave;m mịn sợi vải, chống nhăn, bảo vệ bề mặt &aacute;o quần kh&ocirc;ng bị kh&ocirc; xơ.</span></span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Redox &amp; C&aacute;c Enzyme hỗ trợ kh&aacute;c: Tăng cường kh&aacute;ng khuẩn, khử m&ugrave;i ẩm mốc v&agrave; ngăn chặn c&aacute;c hạt bụi bẩn b&aacute;m ngược trở lại sợi vải trong qu&aacute; tr&igrave;nh giặt.</span></span></span></span></li>\r\n</ul>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#003399\">2. Giải ph&aacute;p 2 trong 1: Giặt Sạch S&acirc;u - Xả Mềm Vải &amp; Lưu Hương Suốt 7 Ng&agrave;y</span></span></span></strong></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Kh&ocirc;ng c&ograve;n cảnh lỉnh kỉnh chai lọ hay tốn th&ecirc;m chi ph&iacute; cho nước xả vải ri&ecirc;ng biệt, Booster t&iacute;ch hợp ho&agrave;n hảo cả hai t&iacute;nh năng:</span></span></span></span></p>\r\n\r\n<ul>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Sạch s&acirc;u vượt trội: C&ocirc;ng thức đậm đặc gấp 5 lần th&ocirc;ng thường, hạt bọt mịn dễ d&agrave;ng len lỏi v&agrave;o từng thớ vải gi&uacute;p &#39;Đ&aacute;nh bay vết bẩn chỉ trong 1 lần giặt&#39; (Remove stains with just 1 wash).</span></span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Lưu hương bền l&acirc;u: Hương hoa thi&ecirc;n nhi&ecirc;n tươi m&aacute;t, dịu nhẹ phảng phất suốt cả ng&agrave;y d&agrave;i. Quần &aacute;o sau khi phơi kh&ocirc; giữ hương thơm bền bỉ đến hơn 7 ng&agrave;y, bất chấp thời tiết nồm ẩm.</span></span></span></span></li>\r\n</ul>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#003399\">3. Bảo vệ m&agrave;u sắc quần &aacute;o bền l&acirc;u sau 100 lần giặt (Color Care)</span></span></span></strong></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Nhờ c&ocirc;ng nghệ Color Care ti&ecirc;n tiến kết hợp ti&ecirc;u chuẩn ch&acirc;u &Acirc;u (European Standard), nước giặt xả Booster giữ cho trang phục lu&ocirc;n tươi mới, kh&ocirc;ng l&agrave;m phai m&agrave;u hay bạc m&agrave;u vải ngay cả sau 100 lần giặt. Quần &aacute;o trắng giữ được độ trắng s&aacute;ng nguy&ecirc;n bản, quần &aacute;o m&agrave;u kh&ocirc;ng bị loang lổ.</span></span></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><strong><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#003399\">4. An to&agrave;n tuyệt đối cho gia đ&igrave;nh v&agrave; th&acirc;n thiện với m&aacute;y giặt</span></span></span></strong></span></span></p>\r\n\r\n<ul>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Độ l&agrave;nh t&iacute;nh cao: Th&agrave;nh phần enzyme sinh học v&ocirc; c&ugrave;ng dịu nhẹ, an to&agrave;n tuyệt đối cho da tay (kh&ocirc;ng g&acirc;y kh&ocirc; r&aacute;p) v&agrave; c&oacute; thể sử dụng an to&agrave;n cho cả quần &aacute;o của trẻ sơ sinh, trẻ nhỏ.</span></span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Bảo vệ m&aacute;y giặt: Lượng bọt được kiểm so&aacute;t ở mức vừa phải, gi&uacute;p bảo vệ động cơ m&aacute;y giặt (cả m&aacute;y cửa tr&ecirc;n v&agrave; cửa ngang), kh&ocirc;ng để lại cặn bột giặt g&acirc;y hỏng m&aacute;y hay b&aacute;m kết tủa trắng tr&ecirc;n quần &aacute;o.</span></span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Minh bạch nguồn gốc: Bao b&igrave; c&oacute; t&iacute;ch hợp m&atilde; QR code, gi&uacute;p người ti&ecirc;u d&ugrave;ng dễ d&agrave;ng qu&eacute;t m&atilde; truy xuất nguồn gốc sản phẩm ch&iacute;nh h&atilde;ng của S Việt AAB.</span></span></span></span></li>\r\n</ul>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><strong><span style=\"font-size:16.0pt\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#003399\">III. TH&Ocirc;NG TIN QUY C&Aacute;CH V&Agrave; HƯỚNG DẪN SỬ DỤNG</span></span></span></strong></span></span></p>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><strong><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Th&ocirc;ng số sản phẩm từ nh&agrave; sản xuất:</span></span></strong></span></span></p>\r\n\r\n<ul>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Thương hiệu: Booster (Thuộc C&ocirc;ng ty TNHH H&oacute;a Mỹ Phẩm S Việt AAB - Nh&agrave; m&aacute;y tại KCN Vĩnh Kh&uacute;c, Hưng Y&ecirc;n).</span></span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Quy c&aacute;ch đ&oacute;ng g&oacute;i: T&uacute;i c&oacute; v&ograve;i tiện lợi 3.7kg (Th&ugrave;ng gồm 4 t&uacute;i x 3.7kg - Tổng khối lượng 14.8kg cực kỳ tiết kiệm).</span></span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">T&iacute;nh kinh tế: Thiết kế chương tr&igrave;nh si&ecirc;u tiết kiệm gi&uacute;p người ti&ecirc;u d&ugrave;ng tiết kiệm chi ph&iacute; l&ecirc;n đến 96.000đ so với mua lẻ th&ocirc;ng thường.</span></span></span></span></li>\r\n</ul>\r\n\r\n<p><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><strong><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Hướng dẫn sử dụng hiệu quả:</span></span></strong></span></span></p>\r\n\r\n<ul>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Giặt m&aacute;y: Sử dụng 1 nắp (khoảng 65ml) nước giặt Booster cho một lần giặt th&ocirc;ng thường (khoảng 15 - 20 chiếc quần &aacute;o bẩn). Điều chỉnh lượng nước giặt t&ugrave;y theo độ bẩn v&agrave; số lượng đồ.</span></span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Giặt tay: H&ograve;a 1/2 nắp v&agrave;o 3 - 5 l&iacute;t nước, ng&acirc;m quần &aacute;o khoảng 15 ph&uacute;t, v&ograve; nhẹ v&agrave; xả lại sạch với nước.</span></span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">Mẹo xử l&yacute; vết bẩn cứng đầu: Thoa trực tiếp một &iacute;t nước giặt Booster l&ecirc;n vết bẩn, tr&agrave; nhẹ rồi cho v&agrave;o m&aacute;y giặt b&igrave;nh thường.</span></span></span></span><br />\r\n	<br />\r\n	<span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\"><span style=\"font-size:18px\"><strong>Gi&aacute; b&aacute;n:</strong></span> </span></span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">130.000/ t&uacute;i (3.7 kg)</span></span></span></span></li>\r\n	<li><span style=\"font-size:11pt\"><span style=\"font-family:Cambria,serif\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\"><span style=\"color:#333333\">500.000/ th&ugrave;ng (4 t&uacute;i)</span></span></span></span></li>\r\n</ul>\r\n','BEMBKN4K_z7996470764848_cfc1e699ee87841b43ced9541a34eee7.jpg','',0,130000,NULL,NULL,'2026-06-01','vn',1,1,'','','Đánh Bay Vết Bẩn Chỉ Trong 1 Lần Giặt Với Siêu Phẩm Nước Giặt Xả Booster 6 Enzyme Mới','',NULL,'',NULL,0,'','','','',NULL,NULL,'',NULL,'','','','',1),(110,48,'Nước hồng sâm 6 năm tuổi Korea Red Ginseng Drink (30 gói x 70 ml)','nuoc-hong-sam-6-nam-tuoi-korea-red-ginseng-drink-30-goi-x-70-ml','Nước hồng sâm 6 năm tuổi Korea Red Ginseng Drink (xách 30 gói)','<h2><strong>Th&agrave;nh phần</strong></h2>\r\n\r\n<p>- Chiết xuất từ hồng s&acirc;m nguy&ecirc;n chất 6 năm tuổi của H&agrave;n Quốc, tỷ lệ phối trộn đạt chuẩn 70% rễ ch&iacute;nh v&agrave; 30% rễ phụ.</p>\r\n\r\n<p>- C&aacute;c loại thảo dược qu&yacute;, vitamin, dưỡng chất kh&aacute;c.</p>\r\n\r\n<p>-&nbsp;<a href=\"https://nhansamvang.vn/collections/nhan-sam-han-quoc\">Nh&acirc;n s&acirc;m</a>&nbsp;chất lượng cao được kiểm so&aacute;t nghi&ecirc;m ngặt từ khi gieo trồng đến khi thu hoạch v&agrave; chế biến nhằm đảm bảo c&aacute;c sản phẩm hồng s&acirc;m khi đến tay kh&aacute;ch h&agrave;ng đều mang lại những gi&aacute; trị cao nhất cho sức khỏe.</p>\r\n\r\n<h2><strong>C&ocirc;ng dụng</strong></h2>\r\n\r\n<p>- Cải thiện sức khỏe, tăng cường sức đề kh&aacute;ng cho cơ thể.</p>\r\n\r\n<p>- Rất c&oacute; lợi cho sức khỏe người cao tuổi, cải thiện c&aacute;c bệnh tuổi gi&agrave; như tiểu đường, huyết &aacute;p, mỡ m&aacute;u, đồng thời t&aacute;c động l&ecirc;n to&agrave;n bộ cơ quan của cơ thể.</p>\r\n\r\n<p>- Gi&uacute;p an thần, giảm stress, giảm căng thẳng, mệt mỏi v&agrave; thư giản đầu &oacute;c, gi&uacute;p cải thiện giấc ngủ cho bạn giấc ngủ s&acirc;u v&agrave; ngon hơn, từ đ&oacute; cải thiện được chất lượng c&ocirc;ng việc.</p>\r\n\r\n<p>- Gi&uacute;p ổn định huyết &aacute;p, cải thiện sức khỏe tim mạch, hỗ trợ hệ tuần ho&agrave;n hoạt động ổn định, k&iacute;ch th&iacute;ch tăng cường sản sinh hồng cầu ở tủy gi&uacute;p ngăn ngừa xơ vữa động mặc, giảm cholesterol ngăn ngừa nguy cơ tiểu đường.<br />\r\n&nbsp;</p>\r\n\r\n<h2><strong>Hướng dẫn sử dụng</strong></h2>\r\n\r\n<p>- Mỗi ng&agrave;y n&ecirc;n d&ugrave;ng nước &eacute;p hồng s&acirc;m từ 1 đến 2 lần, mỗi lần 1 g&oacute;i.</p>\r\n\r\n<p>- Uống&nbsp;<a href=\"https://nhansamvang.vn/collections/nuoc-hong-sam-han-quoc\">nước hồng s&acirc;m</a>&nbsp;để lạnh sẽ ngon miệng hơn.</p>\r\n\r\n<p><strong>Th&ocirc;ng Tin Sản Phẩm</strong></p>\r\n\r\n<p><u>Thương hiệu</u>: KGC</p>\r\n\r\n<p><u>Quy c&aacute;ch</u>: 30 g&oacute;i x 70ml</p>\r\n\r\n<p><u>Xuất xứ</u>: H&agrave;n Quốc</p>\r\n','BEMHUODP_Untitled-1.png','',0,1900000,NULL,NULL,'2026-07-01','vn',1,1,'','','','',NULL,'',NULL,0,'','','','',NULL,NULL,'',NULL,'','','','',1),(111,48,'Tinh Chất Nước Mát Gan Punggi Đậm Đặc Hàn Quốc - 30 gói x 60ml','tinh-chat-nuoc-mat-gan-punggi-dam-dac-han-quoc--30-goi-x-60ml','','<h4><strong>Th&agrave;nh Phần:</strong></h4>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<ul>\r\n	<li>Chiết xuất quả kh&uacute;ng kh&eacute;ng hovenia dulcis [Nước tinh khiết, th&acirc;n c&acirc;y hovenia dulcis (H&agrave;n Quốc) 19,5%, quả hovenia dulcis (H&agrave;n Quốc) 10,5%] 78,4%, Isomaltooligosaccharide, Đường (xi-r&ocirc; tinh bột), hỗn hợp thực vật c&ocirc; đặc, axit xitric, chiết xuất hạt bưởi.</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h4><strong>C&ocirc;ng dụng:</strong></h4>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<ul>\r\n	<li>T&aacute;c dụng giải độc gan, thải độc gan, tăng cường c&aacute;c chức năng gan hiệu quả.</li>\r\n	<li>D&ugrave;ng cho bệnh nh&acirc;n ung thư gan, suy giảm chức năng gan</li>\r\n	<li>Người hay bị mụn nhọt, n&oacute;ng trong do d&ugrave;ng bia rượu</li>\r\n	<li>C&ocirc;ng dụng giải rượu cũng rất tốt</li>\r\n</ul>\r\n\r\n<h4><strong>Đối tượng sử dụng:</strong></h4>\r\n\r\n<ul>\r\n	<li>Người uống rượu bia nhiều.</li>\r\n	<li>N&oacute;ng trong người, mụn nhọt, dị ứng. Người cần thanh nhiệt giải độc cơ thể, gầy yếu, cơ thể suy kiệt do gan k&eacute;m.</li>\r\n	<li>Người bị bệnh về gan, suy gan</li>\r\n	<li>Người uống thuốc t&acirc;y trong thời gian d&agrave;i</li>\r\n</ul>\r\n\r\n<h4><strong>Hướng dẫn sử dụng:</strong></h4>\r\n\r\n<ul>\r\n	<li>ng&agrave;y uống 1 g&oacute;i, x&eacute; trực tiếp g&oacute;i hoặc đổ ra cốc uống</li>\r\n</ul>\r\n\r\n<h4><strong>Bảo quản:</strong></h4>\r\n\r\n<ul>\r\n	<li>Bảo quản nơi kh&ocirc; r&aacute;o tho&aacute;ng m&aacute;t</li>\r\n	<li>Hạn sử dụng ghi tr&ecirc;n bao b&igrave;</li>\r\n</ul>\r\n','BEMHVNID_23.png','',0,1900000,NULL,NULL,'2026-06-02','vn',1,1,'','','','',NULL,'',NULL,0,'','','','',NULL,NULL,'',NULL,'','','','',1),(112,48,'Combo Thuận Phát 1','combo-thuan-phat-1','','<p>&nbsp;</p>\r\n\r\n<p><strong>COMBO THUẬN PH&Aacute;T 1 BAO GỒM<br />\r\n1 dung dịch xoa b&oacute;p QL Group 100ml: 1.150.000 VNĐ<br />\r\n2 hộp VEGAN MEALS: 2.300.000 VND<br />\r\n1 hộp GREEN: 1.250.000 VNĐ<br />\r\n1 hộp nội tiết tố nữ 2XH Plus</strong><br />\r\n&nbsp;</p>\r\n','14LEJ6HS_combo1.png','',0,5550000,NULL,NULL,'2026-07-03','vn',1,1,'','','','',NULL,'',NULL,1,'','','','',NULL,NULL,'',NULL,'','','','',1),(114,48,'Combo Thuận Phát 3','combo-thuan-phat-3','','<p>&nbsp;</p>\r\n\r\n<p><strong>COMBO THUẬN PH&Aacute;T 3 BAO GỒM<br />\r\n2 dung dịch xoa b&oacute;p QL Group 100ml: 2.250.000 VNĐ<br />\r\n1 hộp VEGAN MEALS: 1.150.000 VND<br />\r\n1 hộp GREEN: 1.250.000 VNĐ<br />\r\n1 hộp nội tiết tố nữ 2XH Plus</strong></p>\r\n','BEMI5R6N_combo3.png','',0,5550000,NULL,NULL,'2026-07-02','vn',1,1,'','','','',NULL,'',NULL,1,'','','','',NULL,NULL,'',NULL,'','','','',1),(115,48,'Combo Thuận Phát 4','combo-thuan-phat-4','','<p>&nbsp;</p>\r\n\r\n<p><strong>COMBO&nbsp;THUẬN PH&Aacute;T 4 BAO GỒM<br />\r\n5 dung dịch xoa b&oacute;p QL Group 100ml: 5.750.000 VNĐ</strong></p>\r\n','BEMI6IR6_combo4.png','',0,5750000,NULL,NULL,'2026-07-02','vn',1,1,'','','','',NULL,'',NULL,1,'','','','',NULL,NULL,'',NULL,'','','','',1),(116,48,'Combo Thuận Phát 5','combo-thuan-phat-5','','<p><strong>COMBO THUẬN PH&Aacute;T 5 BAO GỒM<br />\r\n5 hộp VEGAN MEALS: 5.750.000 VND</strong></p>\r\n','BEMI7189_combo5.png','',0,5750000,NULL,NULL,'2026-07-02','vn',1,1,'','','','',NULL,'',NULL,1,'','','','',NULL,NULL,'',NULL,'','','','',1),(117,48,'Combo Thuận Phát 6','combo-thuan-phat-6','','<p>&nbsp;</p>\r\n\r\n<p><strong>COMBO THUẬN PH&Aacute;T 6 BAO GỒM<br />\r\n4 dung dịch xoa b&oacute;p QL Group 10ml: 480.000 VNĐ<br />\r\n4 hộp GREEN: 1.250.000 VNĐ</strong></p>\r\n','BEMJE2SL_combo6.png','',0,5480000,NULL,NULL,'2026-07-02','vn',1,1,'','','','',NULL,'',NULL,1,'','','','',NULL,NULL,'',NULL,'','','','',1);
