INSERT INTO `sys_worldwide` VALUES (208,'Chị Nguyễn Thu Trang','','CEO Aoquee','','<p>M&igrave;nh rất th&iacute;ch học Golf kiểu nhiều c&ocirc;ng cụ v&agrave; m&aacute;y m&oacute;c hiện đại như Snaggolf</p>\r\n','B38F2GAG_AUMQTV8S_AMAL8I7N_AFRK7INH_4.jpg',1,'vn',1,0,'','Chi-Nguyen-Thu-Trang',631),(209,'Nguyễn Mai An','Khóa chỉnh dáng Swing dành cho chị em quả bá đạo','Giám đốc điều hành nhà hàng: Ao Quê Restaurent','','<p>M&igrave;nh biết chơi Golf l&acirc;u rồi nhưng cứ bị ch&ecirc; cục mịch, nhờ Viewgolf m&agrave; d&aacute;ng m&igrave;nh kh&aacute;c hẳn khi Swing, Snag-golf quả b&aacute; đạo</p>\r\n','B81L1FEC_Screenshot_4.jpg',2,'vn',1,0,'','Nguyen-Mai-An',631),(210,'Bà Nguyễn Thanh Nguyệt','Tôi đến với Viewgolf vì Snag-golf là chuẩn nhất TG','Nhân Viên Kế Toán','','<p>Snag-golf trực quan, nhiều c&ocirc;ng cụ hỗ trợ n&ecirc;n gi&uacute;p người tập tăng gấp 3 lần thời gian tập Golf, l&agrave;m c&uacute; đ&aacute;nh ch&iacute;nh x&aacute;c hơn 5 lần so với b&igrave;nh thường. Ch&iacute;nh v&igrave; thế Snag-golf được đưa v&agrave;o đ&agrave;o tạo nhượng quyền chuẩn Quốc tế v&agrave; l&agrave; hệ thống đ&agrave;o tạo Golf lớn nhất Thế giới !</p>\r\n','B38F2IEP_AUMQU760_AMAL8PG9_AFRK7OIS_1.jpg',3,'vn',1,0,'','Ba-Nguyen-Thanh-Nguyet',631),(212,'Anh Dũng - Đống Đa','Học Viewgolf quá hay','','','<p><span style=\"color:#444444; font-family:Inter,sans-serif; font-size:16px\">Kiểu học Golf từ A-Z qu&aacute; hay, học xong ra s&acirc;n lu&ocirc;n</span></p>\r\n','B38F2SJA_B2HSMEMF_AUMQUCE3_AMAL7QHD_AFRK7N5E_2.jpg',2,'vn',1,0,'','Anh-Dung--Dong-Da',631),(213,'Anh Hưng - Thanh Xuân','Học quá hay và dễ','','','<p><span style=\"color:#444444; font-family:Inter,sans-serif; font-size:16px\">Gia đ&igrave;nh m&igrave;nh đi học Snag-golf v&igrave; đ&atilde; biết v&agrave; tập khi c&ocirc;ng t&aacute;c tại H&agrave;n Quốc</span></p>\r\n','B38F3B1F_B2SPU5T9_58622746_275935456627007_6261272335643312128_n.jpg',3,'vn',1,0,'','Anh-Hung--Thanh-Xuan',631),(215,'Bùi Kim Hà','','','','<p>M&ocirc;̣t ngày làm vi&ecirc;̣c v&acirc;́t vả&nbsp;bữa ăn ngon&nbsp;r&acirc;́t quan trọng c&acirc;̀n chọn được&nbsp;nguy&ecirc;n li&ecirc;̣u sạch đảm bảo dinh dưỡng, đặc bi&ecirc;̣t mang hương vị qu&ecirc; nhà.</p>\r\n','14CMC0OF_B38F2GAG_AUMQTV8S_AMAL8I7N_AFRK7INH_4.jpg',0,'vn',0,0,'','Bui-Kim-Ha',677),(216,'Vũ Quang Hoàng','','Kỹ sư','','<p>Cùng thưởng thức các m&oacute;n ăn ngon của Việt Nam theo v&ugrave;ng miền nh&acirc;́t định kh&ocirc;ng n&ecirc;n bỏ qua với nguy&ecirc;n li&ecirc;̣u tươi ngon, sạch đ&ecirc;̉ ch&ecirc;́ bi&ecirc;́n&nbsp;bữa ăn gia đình nhé.&nbsp;</p>\r\n','BBUVOADB_B38F2SJA_B2HSMEMF_AUMQUCE3_AMAL7QHD_AFRK7N5E_2.jpg',0,'vn',0,0,'','Vu-Quang-Hoang',677),(217,'Đặng Khánh Chi','','','','<p>Affiliate l&agrave; h&igrave;nh thức kiếm tiền dễ bắt đầu nhất hiện nay. V&igrave; thế c&oacute; nhiều mẹ bỉm sữa, sinh vi&ecirc;n, thậm ch&iacute; nh&acirc;n vi&ecirc;n văn ph&ograve;ng muốn kiếm th&ecirc;m thu nhập ngo&agrave;i đều c&oacute; thể l&agrave;m được.</p>\r\n','14CMC1JF_B38F2IEP_AUMQU760_AMAL8PG9_AFRK7OIS_1.jpg',1,'vn',1,0,'','Dang-Khanh-Chi',677),(218,'Nguyễn Văn Tuấn','','Kinh doanh','','<p>Qua giới thiệu của bạn b&egrave;, t&ocirc;i đ&atilde; biết đến Thuận Ph&aacute;t. Sản phẩm của Thuận Ph&aacute;t cung cấp rất tốt, t&ocirc;i rất tin tưởng n&ecirc;n đ&atilde; sửa dụng nhiều v&agrave; tham gia&nbsp;Affiliate của Thuận Ph&aacute;t để giới thiệu cho bạn b&egrave;.</p>\r\n\r\n<p>C&aacute;m ơn c&ocirc;ng ty !</p>\r\n','BBUVOK7I_B38F3B1F_B2SPU5T9_58622746_275935456627007_6261272335643312128_n.jpg',0,'vn',0,0,'','Nguyen-Van-Tuan',677),(219,'Nguyễn Thị Thúy','','','','<p>Qua giới thiệu của bạn b&egrave;, t&ocirc;i đ&atilde; biết đến Thuận Ph&aacute;t. Sản phẩm của Thuận Ph&aacute;t cung cấp rất tốt, t&ocirc;i rất tin tưởng n&ecirc;n đ&atilde; sửa dụng nhiều v&agrave; tham gia&nbsp;Affiliate của Thuận Ph&aacute;t để giới thiệu cho bạn b&egrave;. T&ocirc;i rất vui v&igrave; vừa c&oacute; sản phẩm tốt để d&ugrave;ng vừa c&oacute; được nguồn thu nhập ổn định v&agrave; hiệu quả.</p>\r\n\r\n<p>C&aacute;m ơn c&ocirc;ng ty rất nhiều !</p>\r\n','14CMC25M_B38F2HET_132932PN_p_wbps.jpg',0,'vn',0,0,'','Nguyen-Thi-Thuy',677),(220,'Chị Hương','','','','<p>Qua giới thiệu của bạn b&egrave; t&ocirc;i đ&atilde; biết đến Thuận Ph&aacute;t. C&aacute;c bạn nh&acirc;n vi&ecirc;n tư vấn rất nhiệt t&igrave;nh v&agrave; cẩn thận. T&ocirc;i đ&atilde; c&oacute; được nguồn thu nhập ổn định v&agrave; hiệu quả khi tham gia&nbsp;Affiliate (tiếp thị li&ecirc;n kết) của Thuận Ph&aacute;t.</p>\r\n','BC1KQMBD_1.jpg',11,'vn',1,0,'','Chi-Huong',677);
/*!40000 ALTER TABLE `sys_worldwide` ENABLE KEYS */;
